  1→import {
  2→  conversationSchema,
  3→  normalizedSnapshotPayloadSchema,
  4→} from "@chat-exporter/shared";
  5→import { acquireContext, releaseContext } from "./browser-pool.js";
  6→import { MAX_MESSAGE_COUNT, MAX_RAW_HTML_BYTES } from "./constants.js";
  7→import { applyOpenAiStructuring } from "./openai-structuring.js";
  8→import {
  9→  blockNonEssentialResources,
 10→  preparePageScripts,
 11→  truncateMessagesIfNeeded,
 12→  validateRawHtmlSize,
 13→} from "./parser-page-utils.js";
 14→import type { PlatformParserResult, StageCallback } from "./parser-types.js";
 15→
 16→/* ── Claude share-import constants ─────────────────────────── */
 17→
 18→/** Timeout for the initial page.goto() navigation. */
 19→export const PAGE_LOAD_TIMEOUT_MS = 30_000;
 20→
 21→/** Timeout for waiting until message elements appear in the DOM. */
 22→export const MESSAGE_WAIT_TIMEOUT_MS = 20_000;
 23→
 24→/** Extra delay after messages appear to let the page stabilize. */
 25→export const PAGE_STABILIZATION_MS = 1_000;
 26→
 27→/* ─────────────────────────────────────────────────────────── */
 28→
 29→export async function importClaudeSharePage(
 30→  url: string,
 31→  options?: { onStage?: StageCallback },
 32→): Promise<PlatformParserResult> {
 33→  const context = await acquireContext();
 34→
 35→  try {
 36→    await blockNonEssentialResources(context);
 37→
 38→    const page = await context.newPage();
 39→    await preparePageScripts(page);
 40→
 41→    options?.onStage?.("fetch");
 42→    await page.goto(url, {
 43→      waitUntil: "domcontentloaded",
 44→      timeout: PAGE_LOAD_TIMEOUT_MS,
 45→    });
 46→    await page.waitForFunction(
 47→      () => {
 48→        const root =
 49→          document.querySelector("main, [role='main'], article, body") ??
 50→          document.body;
 51→        return (root.textContent ?? "").trim().length > 32;
 52→      },
 53→      {
 54→        timeout: MESSAGE_WAIT_TIMEOUT_MS,
 55→      },
 56→    );
 57→    await page.waitForTimeout(PAGE_STABILIZATION_MS);
 58→
 59→    options?.onStage?.("extract");
 60→    const extracted = await page.evaluate(() => {
 61→      const { normalizeWhitespace, elementToBlocks } = globalThis.__domKit;
 62→
 63→      function normalizeTitle(rawTitle: string) {
 64→        return (
 65→          rawTitle.replace(/^Claude\s*[-–—|]\s*/i, "").trim() || "Untitled Chat"
 66→        );
 67→      }
 68→
 69→      const warnings: string[] = [];
 70→
 71→      // Strategy 1: Look for data-testid based turn containers
 72→      // Claude share pages typically use [data-testid] patterns
 73→      const turnSelectors = [
 74→        '[data-testid*="conversation-turn"]',
 75→        '[data-testid*="chat-turn"]',
 76→        '[data-testid*="message"]',
 77→        ".conversation-turn",
 78→        ".chat-message",
 79→      ];
 80→
 81→      let turnElements: Element[] = [];
 82→      for (const selector of turnSelectors) {
 83→        turnElements = Array.from(document.querySelectorAll(selector));
 84→        if (turnElements.length >= 2) break;
 85→      }
 86→
 87→      // Strategy 2: If no explicit turns found, look for role-based containers
 88→      if (turnElements.length < 2) {
 89→        const allMessages = Array.from(
 90→          document.querySelectorAll(
 91→            '[class*="human"], [class*="user"], [data-role="human"], [data-role="user"], [class*="assistant"], [data-role="assistant"]',
 92→          ),
 93→        );
 94→        if (allMessages.length >= 2) {
 95→          turnElements = allMessages;
 96→        }
 97→      }
 98→
 99→      // Strategy 3: Content-based heuristic
100→      if (turnElements.length < 2) {
101→        const mainContent = document.querySelector(
102→          'main, [role="main"], .conversation, .chat-content',
103→        );
104→        if (mainContent) {
105→          const candidates = Array.from(mainContent.children).filter(
106→            (child) => {
107→              const text = (child.textContent ?? "").trim();
108→              return text.length > 5 && child.children.length > 0;
109→            },
110→          );
111→          if (candidates.length >= 2) {
112→            turnElements = candidates;
113→            warnings.push(
114→              "Used content heuristic to identify messages — extraction quality may vary.",
115→            );
116→          }
117→        }
118→      }
119→
120→      if (turnElements.length === 0) {
121→        return {
122→          title: normalizeTitle(document.title),
123→          messages: [],
124→          warnings: ["No conversation turns found on Claude share page."],
125→        };
126→      }
127→
128→      let fallbackCount = 0;
129→      const messages = turnElements
130→        .map((turn, index) => {
131→          // Determine role
132→          const testId = turn.getAttribute("data-testid") ?? "";
133→          const dataRole = turn.getAttribute("data-role") ?? "";
134→          const className = (turn.className ?? "").toLowerCase();
135→
136→          let role = "unknown";
137→          if (
138→            dataRole === "human" ||
139→            dataRole === "user" ||
140→            className.includes("human") ||
141→            className.includes("user") ||
142→            testId.includes("user") ||
143→            testId.includes("human")
144→          ) {
145→            role = "user";
146→          } else if (
147→            dataRole === "assistant" ||
148→            className.includes("assistant") ||
149→            testId.includes("assistant")
150→          ) {
151→            role = "assistant";
152→          } else {
153→            // Alternating pattern: even indices = user, odd = assistant
154→            role = index % 2 === 0 ? "user" : "assistant";
155→            if (turnElements.length > 1) {
156→              warnings.push(
157→                `Inferred role for message ${index + 1} as "${role}" from position.`,
158→              );
159→            }
160→          }
161→
162→          const messageId =
163→            turn.getAttribute("data-message-id") ??
164→            turn.getAttribute("data-testid") ??
165→            crypto.randomUUID();
166→
167→          // Extract blocks
168→          const contentRoot =
169→            turn.querySelector(
170→              '.markdown, .prose, .message-content, [class*="content"]',
171→            ) ?? turn;
172→          const blocks = Array.from(contentRoot.childNodes).flatMap(
173→            (childNode) => {
174→              if (childNode.nodeType === Node.TEXT_NODE) {
175→                const text = normalizeWhitespace(childNode.textContent ?? "");
176→                return text ? [{ type: "paragraph" as const, text }] : [];
177→              }
178→              if (childNode.nodeType !== Node.ELEMENT_NODE) return [];
179→              return elementToBlocks(childNode as Element);
180→            },
181→          );
182→
183→          const rawText = normalizeWhitespace(
184→            (turn as HTMLElement).innerText ?? turn.textContent ?? "",
185→          );
186→
187→          if (blocks.length === 0 && rawText) {
188→            fallbackCount++;
189→            return {
190→              id: messageId,
191→              role,
192→              rawText,
193→              rawHtml: (turn as HTMLElement).innerHTML,
194→              blocks: [{ type: "paragraph" as const, text: rawText }],
195→              parser: {
196→                source: "claude-fallback",
197→                blockCount: 1,
198→                usedFallback: true,
199→                strategy: "fallback" as const,
200→              },
201→            };
202→          }
203→
204→          if (blocks.length === 0) return null;
205→
206→          return {
207→            id: messageId,
208→            role,
209→            rawText,
210→            rawHtml: (turn as HTMLElement).innerHTML,
211→            blocks,
212→            parser: {
213→              source: "claude-structured",
214→              blockCount: blocks.length,
215→              usedFallback: false,
216→              strategy: "deterministic" as const,
217→            },
218→          };
219→        })
220→        .filter(Boolean);
221→
222→      if (fallbackCount > 0) {
223→        warnings.push(
224→          `${fallbackCount} message(s) fell back to plain paragraph.`,
225→        );
226→      }
227→
228→      return { title: normalizeTitle(document.title), messages, warnings };
229→    });
230→
231→    options?.onStage?.("normalize");
232→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
233→    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
234→
235→    options?.onStage?.("structure");
236→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
237→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
238→      ...normalizedPayload,
239→      messages: structured.messages,
240→      warnings: [...normalizedPayload.warnings, ...structured.warnings],
241→      structuring: structured.structuring,
242→    });
243→
244→    const rawHtml = await page.content();
245→    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
246→    const fetchedAt = new Date().toISOString();
247→
248→    const conversation = conversationSchema.parse({
249→      id: crypto.randomUUID(),
250→      title: finalPayload.title,
251→      source: {
252→        url,
253→        platform: "claude",
254→      },
255→      messages: finalPayload.messages,
256→    });
257→
258→    return {
259→      conversation,
260→      warnings: finalPayload.warnings,
261→      snapshot: {
262→        finalUrl: page.url(),
263→        fetchedAt,
264→        pageTitle: finalPayload.title,
265→        rawHtml,
266→        normalizedPayload: finalPayload,
267→        fetchMetadata: {
268→          articleCount: normalizedPayload.messages.length,
269→          messageCount: conversation.messages.length,
270→          rawHtmlBytes,
271→        },
272→      },
273→    };
274→  } finally {
275→    await releaseContext(context);
276→  }
277→}
