  1→import {
  2→  conversationSchema,
  3→  normalizedSnapshotPayloadSchema,
  4→} from "@chat-exporter/shared";
  5→import { acquireContext, releaseContext } from "./browser-pool.js";
  6→import { MAX_MESSAGE_COUNT, MAX_RAW_HTML_BYTES } from "./constants.js";
  7→import { applyOpenAiStructuring } from "./openai-structuring.js";
  8→import {
  9→  blockNonEssentialResources,
 10→  preparePageScripts,
 11→  truncateMessagesIfNeeded,
 12→  validateRawHtmlSize,
 13→} from "./parser-page-utils.js";
 14→import type { PlatformParserResult, StageCallback } from "./parser-types.js";
 15→import { looksLikeSharedConversationUrl } from "./source-platform.js";
 16→
 17→/* ── DeepSeek share-import constants ─────────────────────── */
 18→
 19→/** Timeout for the initial page.goto() navigation. */
 20→export const PAGE_LOAD_TIMEOUT_MS = 30_000;
 21→
 22→/** Timeout for waiting until message elements appear in the DOM. */
 23→export const MESSAGE_WAIT_TIMEOUT_MS = 20_000;
 24→
 25→/** Extra delay after messages appear to let the page stabilize. */
 26→export const PAGE_STABILIZATION_MS = 1_200;
 27→
 28→/* ─────────────────────────────────────────────────────────── */
 29→
 30→export async function importDeepSeekSharePage(
 31→  url: string,
 32→  options?: {
 33→    onStage?: StageCallback;
 34→  },
 35→): Promise<PlatformParserResult> {
 36→  const context = await acquireContext();
 37→
 38→  try {
 39→    await blockNonEssentialResources(context);
 40→
 41→    const page = await context.newPage();
 42→    await preparePageScripts(page);
 43→
 44→    options?.onStage?.("fetch");
 45→    await page.goto(url, {
 46→      waitUntil: "domcontentloaded",
 47→      timeout: PAGE_LOAD_TIMEOUT_MS,
 48→    });
 49→
 50→    // Wait for meaningful content to appear in the DOM
 51→    await page
 52→      .waitForFunction(
 53→        () => {
 54→          // Strategy 1: DeepSeek-specific selectors
 55→          const specificSelectors = [
 56→            "[data-testid*='message']",
 57→            "[data-testid*='chat']",
 58→            ".ds-message",
 59→            ".chat-message",
 60→            "[class*='message']",
 61→            "[class*='Message']",
 62→            "[role='article']",
 63→          ];
 64→
 65→          for (const selector of specificSelectors) {
 66→            if (document.querySelectorAll(selector).length > 0) {
 67→              return true;
 68→            }
 69→          }
 70→
 71→          // Strategy 2: Look for substantial text content in main area
 72→          const root =
 73→            document.querySelector("main, [role='main'], article, #app") ??
 74→            document.body;
 75→          return (root.textContent ?? "").trim().length > 100;
 76→        },
 77→        { timeout: MESSAGE_WAIT_TIMEOUT_MS },
 78→      )
 79→      .catch(() => undefined);
 80→
 81→    await page.waitForTimeout(PAGE_STABILIZATION_MS);
 82→
 83→    options?.onStage?.("extract");
 84→    const extracted = await page.evaluate(() => {
 85→      const { normalizeWhitespace, elementToBlocks } = globalThis.__domKit;
 86→
 87→      function normalizeTitle(rawTitle: string) {
 88→        const title = rawTitle
 89→          .replace(/\s*[-|]\s*DeepSeek.*$/i, "")
 90→          .replace(/^DeepSeek\s*[-|:]\s*/i, "")
 91→          .replace(/^shared\s+/i, "")
 92→          .trim();
 93→
 94→        return title || "Untitled Chat";
 95→      }
 96→
 97→      function isExcluded(element: Element) {
 98→        return Boolean(
 99→          element.closest(
100→            "nav,header,footer,aside,form,dialog,[role='navigation'],[aria-hidden='true']",
101→          ),
102→        );
103→      }
104→
105→      function isVisible(element: Element) {
106→        const computed = globalThis.getComputedStyle(element as HTMLElement);
107→
108→        if (
109→          computed.display === "none" ||
110→          computed.visibility === "hidden" ||
111→          computed.opacity === "0"
112→        ) {
113→          return false;
114→        }
115→
116→        const rect = (element as HTMLElement).getBoundingClientRect();
117→        return rect.width > 0 && rect.height > 0;
118→      }
119→
120→      function contentRootFor(element: Element) {
121→        return (
122→          element.querySelector(
123→            ".markdown, [data-testid*='markdown'], [class*='markdown'], [data-testid*='response-content'], [data-testid*='message-content'], [data-message-content]",
124→          ) ?? element
125→        );
126→      }
127→
128→      function extractBlocksFromElement(element: Element) {
129→        return Array.from(element.childNodes).flatMap((childNode) => {
130→          if (childNode.nodeType === Node.TEXT_NODE) {
131→            const text = normalizeWhitespace(childNode.textContent ?? "");
132→            return text ? [{ type: "paragraph" as const, text }] : [];
133→          }
134→
135→          if (childNode.nodeType !== Node.ELEMENT_NODE) {
136→            return [];
137→          }
138→
139→          return elementToBlocks(childNode as Element);
140→        });
141→      }
142→
143→      /**
144→       * Extract thinking/reasoning blocks from DeepSeek-R1 responses.
145→       * These are rendered as collapsible or specially marked sections
146→       * showing the model's chain-of-thought reasoning.
147→       */
148→      function extractThinkingBlocks(
149→        element: Element,
150→      ): Array<Record<string, unknown>> {
151→        const thinkingSelectors = [
152→          "[class*='think']",
153→          "[class*='Think']",
154→          "[class*='reason']",
155→          "[class*='Reason']",
156→          "[data-testid*='think']",
157→          "[data-testid*='reason']",
158→          ".ds-think",
159→          ".ds-reasoning",
160→          "details.thinking",
161→          "[class*='chain-of-thought']",
162→        ];
163→
164→        const blocks: Array<Record<string, unknown>> = [];
165→
166→        for (const selector of thinkingSelectors) {
167→          const thinkingElements = element.querySelectorAll(selector);
168→          for (const thinkingEl of thinkingElements) {
169→            const text = normalizeWhitespace(
170→              (thinkingEl as HTMLElement).innerText,
171→            );
172→            if (text) {
173→              blocks.push({
174→                type: "quote" as const,
175→                text: `[Thinking] ${text}`,
176→              });
177→            }
178→          }
179→        }
180→
181→        return blocks;
182→      }
183→
184→      type MessageEntry = {
185→        id: string;
186→        role: "user" | "assistant";
187→        rawText: string;
188→        rawHtml: string;
189→        blocks: Array<Record<string, unknown>>;
190→        parser: {
191→          source: string;
192→          blockCount: number;
193→          usedFallback: boolean;
194→          strategy: "deterministic" | "fallback";
195→        };
196→      };
197→
198→      const warnings: string[] = [];
199→      const messages: MessageEntry[] = [];
200→      let thinkingBlocksFound = 0;
201→      let strategy = "none";
202→
203→      // Strategy 1: Look for DeepSeek-specific message containers
204→      // DeepSeek uses a React SPA — look for common patterns
205→      const strategy1Selectors = [
206→        "[data-testid*='message']",
207→        ".ds-message",
208→        "[class*='chatMessage']",
209→        "[class*='chat-message']",
210→      ];
211→
212→      let turnElements: Element[] = [];
213→
214→      for (const selector of strategy1Selectors) {
215→        const found = Array.from(document.querySelectorAll(selector)).filter(
216→          (el) => isVisible(el) && !isExcluded(el),
217→        );
218→        if (found.length > 0) {
219→          turnElements = found;
220→          strategy = `deepseek-specific(${selector})`;
221→          break;
222→        }
223→      }
224→
225→      // Strategy 2: Look for role-based containers (common in chat UIs)
226→      if (turnElements.length === 0) {
227→        const roleSelectors = [
228→          "[data-role]",
229→          "[data-message-author-role]",
230→          "[role='article']",
231→          "[class*='user'][class*='message'], [class*='assistant'][class*='message']",
232→        ];
233→
234→        for (const selector of roleSelectors) {
235→          const found = Array.from(document.querySelectorAll(selector)).filter(
236→            (el) => isVisible(el) && !isExcluded(el),
237→          );
238→          if (found.length > 0) {
239→            turnElements = found;
240→            strategy = `role-based(${selector})`;
241→            break;
242→          }
243→        }
244→      }
245→
246→      // Strategy 3: Container heuristic fallback — look for alternating
247→      // user/assistant blocks in the main content area
248→      if (turnElements.length === 0) {
249→        const mainRoot =
250→          document.querySelector(
251→            "main, [role='main'], #app > div, #root > div, #__next > div",
252→          ) ?? document.body;
253→
254→        // Look for direct children that could be message turns
255→        const candidates = Array.from(mainRoot.children).filter((el) => {
256→          if (!isVisible(el) || isExcluded(el)) return false;
257→          const text = normalizeWhitespace((el as HTMLElement).innerText ?? "");
258→          return text.length > 10;
259→        });
260→
261→        if (candidates.length >= 2) {
262→          turnElements = candidates;
263→          strategy = "container-heuristic";
264→        }
265→      }
266→
267→      if (turnElements.length === 0) {
268→        return {
269→          title: normalizeTitle(document.title),
270→          messages: [] as MessageEntry[],
271→          warnings: ["No DeepSeek message containers found on this page."],
272→        };
273→      }
274→
275→      turnElements.forEach((element, index) => {
276→        const messageId =
277→          element.getAttribute("data-message-id") ??
278→          element.getAttribute("data-testid") ??
279→          `deepseek-msg-${index + 1}`;
280→
281→        // Determine role from various possible indicators
282→        const roleAttr =
283→          element.getAttribute("data-role") ??
284→          element.getAttribute("data-message-author-role") ??
285→          "";
286→        const classList = (element.className ?? "").toLowerCase();
287→
288→        let role: "user" | "assistant";
289→
290→        if (
291→          roleAttr === "user" ||
292→          classList.includes("user") ||
293→          classList.includes("human")
294→        ) {
295→          role = "user";
296→        } else if (
297→          roleAttr === "assistant" ||
298→          roleAttr === "model" ||
299→          classList.includes("assistant") ||
300→          classList.includes("bot") ||
301→          classList.includes("model") ||
302→          classList.includes("deepseek")
303→        ) {
304→          role = "assistant";
305→        } else {
306→          // Fallback: alternate user/assistant based on position
307→          role = index % 2 === 0 ? "user" : "assistant";
308→        }
309→
310→        // Check for thinking blocks in assistant messages
311→        let thinkingBlocks: Array<Record<string, unknown>> = [];
312→        if (role === "assistant") {
313→          thinkingBlocks = extractThinkingBlocks(element);
314→          if (thinkingBlocks.length > 0) {
315→            thinkingBlocksFound += thinkingBlocks.length;
316→          }
317→        }
318→
319→        const contentRoot = contentRootFor(element);
320→        const rawText = normalizeWhitespace(
321→          (contentRoot as HTMLElement).innerText,
322→        );
323→        const rawHtml = (contentRoot as HTMLElement).innerHTML;
324→
325→        if (!rawText) {
326→          return;
327→        }
328→
329→        if (role === "user") {
330→          messages.push({
331→            id: messageId,
332→            role: "user",
333→            rawText,
334→            rawHtml,
335→            blocks: [{ type: "paragraph", text: rawText }],
336→            parser: {
337→              source: `deepseek-user(${strategy})`,
338→              blockCount: 1,
339→              usedFallback: false,
340→              strategy: "deterministic",
341→            },
342→          });
343→          return;
344→        }
345→
346→        // Assistant message: extract rich blocks
347→        const contentBlocks = extractBlocksFromElement(contentRoot);
348→
349→        // Remove thinking elements from content blocks to avoid duplication
350→        // (they were already extracted separately)
351→        const combinedBlocks = [
352→          ...thinkingBlocks,
353→          ...(contentBlocks.length > 0
354→            ? contentBlocks
355→            : [{ type: "paragraph" as const, text: rawText }]),
356→        ];
357→
358→        const usedFallback = contentBlocks.length === 0;
359→
360→        messages.push({
361→          id: messageId,
362→          role: "assistant",
363→          rawText,
364→          rawHtml,
365→          blocks: combinedBlocks,
366→          parser: {
367→            source: usedFallback
368→              ? `deepseek-assistant-fallback(${strategy})`
369→              : `deepseek-assistant(${strategy})`,
370→            blockCount: combinedBlocks.length,
371→            usedFallback,
372→            strategy: usedFallback ? "fallback" : "deterministic",
373→          },
374→        });
375→      });
376→
377→      if (thinkingBlocksFound > 0) {
378→        warnings.push(
379→          `${thinkingBlocksFound} DeepSeek-R1 thinking/reasoning block(s) were converted to quote blocks prefixed with "[Thinking]".`,
380→        );
381→      }
382→
383→      if (messages.length === 0) {
384→        return {
385→          title: normalizeTitle(document.title),
386→          messages: [] as MessageEntry[],
387→          warnings: [
388→            "DeepSeek message containers found but no extractable messages.",
389→          ],
390→        };
391→      }
392→
393→      warnings.push(
394→        `Parsed ${messages.length} DeepSeek message(s) using strategy: ${strategy}.`,
395→      );
396→
397→      return {
398→        title: normalizeTitle(document.title),
399→        messages,
400→        warnings,
401→      };
402→    });
403→
404→    options?.onStage?.("normalize");
405→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
406→    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
407→
408→    if (normalizedPayload.messages.length === 0) {
409→      throw new Error(
410→        "No importable messages were detected on this DeepSeek page.",
411→      );
412→    }
413→
414→    options?.onStage?.("structure");
415→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
416→    const warnings = [...normalizedPayload.warnings, ...structured.warnings];
417→
418→    if (!looksLikeSharedConversationUrl(url)) {
419→      warnings.push(
420→        "The URL does not look like a typical public share page path, so extraction may be noisier than usual.",
421→      );
422→    }
423→
424→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
425→      ...normalizedPayload,
426→      messages: structured.messages,
427→      warnings,
428→      structuring: structured.structuring,
429→    });
430→    const rawHtml = await page.content();
431→    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
432→    const fetchedAt = new Date().toISOString();
433→
434→    const conversation = conversationSchema.parse({
435→      id: crypto.randomUUID(),
436→      title: finalPayload.title,
437→      source: {
438→        url,
439→        platform: "deepseek",
440→      },
441→      messages: finalPayload.messages,
442→    });
443→
444→    return {
445→      conversation,
446→      warnings: finalPayload.warnings,
447→      snapshot: {
448→        finalUrl: page.url(),
449→        fetchedAt,
450→        pageTitle: finalPayload.title,
451→        rawHtml,
452→        normalizedPayload: finalPayload,
453→        fetchMetadata: {
454→          articleCount: normalizedPayload.messages.length,
455→          messageCount: conversation.messages.length,
456→          rawHtmlBytes,
457→        },
458→      },
459→    };
460→  } finally {
461→    await releaseContext(context);
462→  }
463→}
