 18→/* ── Navigation Timeouts ──────────────────────────────────── */
 19→
 20→/** Navigation timeout for Gemini pages (Google needs longer). */
 21→export const GEMINI_NAVIGATION_TIMEOUT_MS = 60_000;
 22→
 23→/** Timeout for domcontentloaded after initial load. */
 24→export const GEMINI_DOM_CONTENT_LOADED_TIMEOUT_MS = 20_000;
 25→
 26→/** Timeout for the waitForFunction that checks for meaningful content. */
 27→export const GEMINI_FUNCTION_WAIT_TIMEOUT_MS = 20_000;
 28→
 29→/** Timeout for networkidle wait after DOM is ready. */
 30→export const GEMINI_NETWORK_IDLE_TIMEOUT_MS = 5_000;
 31→
 32→/** Extra delay after network-idle to let JS-rendered content settle. */
 33→export const GEMINI_PAGE_STABILIZATION_DELAY_MS = 1_200;
 34→
 35→/* ── Google Consent Handling ──────────────────────────────── */
 36→
 37→/** Timeout for waiting for Google consent buttons to appear. */
 38→const GOOGLE_CONSENT_BUTTON_TIMEOUT_MS = 10_000;
 39→
 40→/** Maximum polling iterations when waiting for navigation after consent dismiss. */
 41→const GOOGLE_CONSENT_DISMISS_MAX_ATTEMPTS = 60;
 42→
 43→/** Polling interval (ms) between checks after clicking the consent button. */
 44→const GOOGLE_CONSENT_POLLING_INTERVAL_MS = 250;
 45→
 46→/** Timeout for domcontentloaded after Google consent redirect. */
 47→const GOOGLE_CONSENT_REDIRECT_TIMEOUT_MS = 15_000;
 48→
 49→/* ── Consent Helpers ──────────────────────────────────────── */
 50→
 51→function normalizeHostname(hostname: string) {
 52→  return hostname.toLowerCase().replace(/^www\./, "");
 53→}
 54→
 55→function isGoogleConsentUrl(urlString: string) {
 56→  const url = new URL(urlString);
 57→  const hostname = normalizeHostname(url.hostname);
 58→
 59→  return (
 60→    hostname === "consent.google.com" ||
 61→    hostname.endsWith(".consent.google.com")
 62→  );
 63→}
 64→
 65→function looksLikeGoogleConsentContent(title: string, previewText: string) {
 66→  const normalizedTitle = title.trim().toLowerCase();
 67→  const normalizedPreview = previewText.trim().toLowerCase();
 68→
 69→  return (
 70→    normalizedTitle === "before you continue" ||
 71→    (normalizedPreview.includes("we use cookies") &&
 72→      normalizedPreview.includes("accept all") &&
 73→      normalizedPreview.includes("reject all"))
 74→  );
 75→}
 76→
 77→async function maybeDismissGoogleConsentGate(page: Page) {
 78→  if (!isGoogleConsentUrl(page.url())) {
 79→    return false;
 80→  }
 81→
 82→  await page
 83→    .waitForSelector('button[jsname="tWT92d"], button[jsname="b3VHJd"]', {
 84→      state: "visible",
 85→      timeout: GOOGLE_CONSENT_BUTTON_TIMEOUT_MS,
 86→    })
 87→    .catch(() => undefined);
 88→
 89→  const rejectAllButton = page.locator('button[jsname="tWT92d"]').first();
 90→  const acceptAllButton = page.locator('button[jsname="b3VHJd"]').first();
 91→
 92→  let actionButton = rejectAllButton;
 93→
 94→  if (!(await actionButton.isVisible().catch(() => false))) {
 95→    actionButton = acceptAllButton;
 96→  }
 97→
 98→  if (!(await actionButton.isVisible().catch(() => false))) {
 99→    return false;
100→  }
101→
102→  await actionButton.click();
103→
104→  for (
105→    let attempt = 0;
106→    attempt < GOOGLE_CONSENT_DISMISS_MAX_ATTEMPTS;
107→    attempt += 1
108→  ) {
109→    if (!isGoogleConsentUrl(page.url())) {
110→      await page
111→        .waitForLoadState("domcontentloaded", {
112→          timeout: GOOGLE_CONSENT_REDIRECT_TIMEOUT_MS,
113→        })
114→        .catch(() => undefined);
115→      return true;
116→    }
117→
118→    await page.waitForTimeout(GOOGLE_CONSENT_POLLING_INTERVAL_MS);
119→  }
120→
121→  return !isGoogleConsentUrl(page.url());
122→}
