 30→/* ─────────────────────────────────────────────────────────── */
 31→
 32→export async function importGrokSharePage(
 33→  url: string,
 34→  options?: {
 35→    onStage?: StageCallback;
 36→  },
 37→): Promise<PlatformParserResult> {
 38→  const context = await acquireContext();
 39→
 40→  try {
 41→    await blockNonEssentialResources(context);
 42→
 43→    const page = await context.newPage();
 44→    await preparePageScripts(page);
 45→
 46→    options?.onStage?.("fetch");
 47→    await page.goto(url, {
 48→      waitUntil: "domcontentloaded",
 49→      timeout: PAGE_LOAD_TIMEOUT_MS,
 50→    });
 51→
 52→    // Grok is a heavy Next.js SPA — wait for meaningful text content to render
 53→    await page
 54→      .waitForFunction(
 55→        () => {
 56→          const root =
 57→            document.querySelector("main, [role='main'], article, body") ??
 58→            document.body;
 59→          return (root.textContent ?? "").trim().length > 32;
 60→        },
 61→        { timeout: GROK_CONTENT_WAIT_TIMEOUT_MS },
 62→      )
 63→      .catch(() => undefined);
 64→
 65→    await page
 66→      .waitForLoadState("networkidle", {
 67→        timeout: GROK_NETWORK_IDLE_TIMEOUT_MS,
 68→      })
 69→      .catch(() => undefined);
 70→    await page.waitForTimeout(GROK_PAGE_STABILIZATION_MS);
 71→
 72→    options?.onStage?.("extract");
 73→    const extracted = await page.evaluate(() => {
 74→      const { normalizeWhitespace, elementToBlocks } = globalThis.__domKit;
 75→
 76→      function normalizeTitle(rawTitle: string) {
 77→        const title = rawTitle
 78→          .replace(/\|\s*shared .*$/i, "")
 79→          .replace(/^(grok|xai)\s*[-|:]\s*/i, "")
 80→          .replace(/^shared\s+/i, "")
 81→          .replace(/\s*\|\s*Shared Grok Conversation$/i, "")
 82→          .trim();
 83→
 84→        return title || "Untitled Chat";
 85→      }
 86→
 87→      function isExcluded(element: Element) {
 88→        return Boolean(
 89→          element.closest(
 90→            "nav,header,footer,aside,form,dialog,[role='navigation'],[aria-hidden='true']",
 91→          ),
 92→        );
 93→      }
 94→
 95→      function isVisible(element: Element) {
 96→        const computed = globalThis.getComputedStyle(element as HTMLElement);
 97→
 98→        if (
 99→          computed.display === "none" ||
100→          computed.visibility === "hidden" ||
101→          computed.opacity === "0"
102→        ) {
103→          return false;
104→        }
105→
106→        const rect = (element as HTMLElement).getBoundingClientRect();
107→        return rect.width > 0 && rect.height > 0;
108→      }
109→
110→      function contentRootFor(element: Element) {
111→        return (
112→          element.querySelector(
113→            ".markdown, [data-testid*='markdown'], [class*='markdown'], [data-testid*='response-content'], [data-testid*='message-content'], [data-message-content]",
114→          ) ?? element
115→        );
116→      }
117→
118→      function attributeHintText(element: Element) {
119→        const node = element as HTMLElement;
120→        return [
121→          element.getAttribute("data-message-author-role") ?? "",
122→          element.getAttribute("data-author-role") ?? "",
123→          element.getAttribute("data-role") ?? "",
124→          element.getAttribute("data-testid") ?? "",
125→          element.getAttribute("aria-label") ?? "",
126→          node.id ?? "",
127→          typeof node.className === "string" ? node.className : "",
128→        ]
129→          .join(" ")
130→          .toLowerCase();
131→      }
132→
133→      function roleFromHints(element: Element): "user" | "assistant" | null {
134→        // Check the element and up to 3 ancestor levels for role hints
135→        const hints: string[] = [];
136→        let current: Element | null = element;
137→
138→        for (let depth = 0; current && depth < 4; depth += 1) {
139→          hints.push(attributeHintText(current));
140→          current = current.parentElement;
141→        }
142→
143→        // Also check child element classes
144→        hints.push(
145→          Array.from(element.querySelectorAll("[class]"))
146→            .slice(0, 24)
147→            .map((node) => ((node as HTMLElement).className || "").toString())
148→            .join(" ")
149→            .toLowerCase(),
150→        );
151→
152→        const hintText = hints.join(" ");
153→
154→        if (
155→          /(^|\b)(user|human|prompt|question|from-user|self-end|justify-end|ml-auto|text-right)(\b|$)/.test(
156→            hintText,
157→          )
158→        ) {
159→          return "user";
160→        }
161→
162→        if (
163→          /(^|\b)(assistant|model|bot|grok|response|answer|self-start|justify-start|mr-auto|text-left)(\b|$)/.test(
164→            hintText,
165→          )
166→        ) {
167→          return "assistant";
168→        }
169→
170→        return null;
171→      }
172→
173→      const warnings: string[] = [];
174→
175→      // Strategy 1: Look for explicit Grok turn/message containers
176→      // Grok share pages use Next.js with various possible selectors
177→      const turnSelectors = [
178→        "[data-testid*='conversation-turn']",
179→        "[data-testid*='chat-turn']",
180→        "[data-testid*='message']",
181→        "[data-message-id]",
182→        "[data-message-author-role]",
183→      ];
184→
185→      let turnElements: Element[] = [];
186→      for (const selector of turnSelectors) {
187→        const found = Array.from(document.querySelectorAll(selector)).filter(
188→          (el) => isVisible(el) && !isExcluded(el),
189→        );
190→        if (found.length >= 2) {
191→          turnElements = found;
192→          break;
193→        }
194→      }
195→
196→      // Strategy 2: Look for role-based containers common in chat UIs
197→      if (turnElements.length < 2) {
198→        const roleContainers = Array.from(
199→          document.querySelectorAll(
200→            "[class*='message'], [class*='turn'], [class*='chat'], [class*='response'], [class*='prompt']",
201→          ),
202→        ).filter((el) => {
203→          if (!isVisible(el) || isExcluded(el)) return false;
204→          const text = normalizeWhitespace((el as HTMLElement).innerText);
205→          return text.length > 2;
206→        });
207→
208→        if (roleContainers.length >= 2) {
209→          turnElements = roleContainers;
210→        }
211→      }
212→
213→      // Strategy 3: Container heuristic — find main content area and extract alternating children
214→      if (turnElements.length < 2) {
215→        const mainContent =
216→          document.querySelector("main") ??
217→          document.querySelector("[role='main']") ??
218→          document.querySelector("article") ??
219→          document.body;
220→
221→        // Look for a repeating container pattern (common in chat UIs)
222→        const candidates = Array.from(
223→          mainContent.querySelectorAll("div,section,article"),
224→        ).filter((el) => {
225→          if (!isVisible(el) || isExcluded(el)) return false;
226→          const children = Array.from(el.children).filter(
227→            (child) =>
228→              isVisible(child) &&
229→              !isExcluded(child) &&
230→              normalizeWhitespace((child as HTMLElement).innerText).length > 10,
231→          );
232→          return children.length >= 2;
233→        });
234→
235→        // Score candidates by number of meaningful direct children
236→        let bestContainer: Element | null = null;
237→        let bestChildCount = 0;
238→
239→        for (const candidate of candidates.slice(0, 100)) {
240→          const children = Array.from(candidate.children).filter((child) => {
241→            if (!isVisible(child) || isExcluded(child)) return false;
242→            const text = normalizeWhitespace((child as HTMLElement).innerText);
243→            return text.length > 10;
244→          });
245→
246→          // Prefer containers whose children have conversation-like hints
247→          const hintedCount = children.filter((child) =>
248→            /(message|turn|chat|prompt|response|assistant|user|grok|human)/i.test(
249→              attributeHintText(child),
250→            ),
251→          ).length;
252→
253→          const score = children.length + hintedCount * 2;
254→          if (score > bestChildCount && children.length >= 2) {
255→            bestChildCount = score;
256→            bestContainer = candidate;
257→          }
258→        }
259→
260→        if (bestContainer) {
261→          turnElements = Array.from(bestContainer.children).filter(
262→            (child) =>
263→              isVisible(child) &&
264→              !isExcluded(child) &&
265→              normalizeWhitespace((child as HTMLElement).innerText).length > 2,
266→          );
267→        }
268→      }
269→
270→      if (turnElements.length === 0) {
271→        return {
272→          title: normalizeTitle(document.title),
273→          messages: [] as Array<{
274→            id: string;
275→            role: "user" | "assistant" | "unknown";
276→            rawText: string;
277→            rawHtml: string;
278→            blocks: Array<Record<string, unknown>>;
279→            parser: {
280→              source: string;
281→              blockCount: number;
282→              usedFallback: boolean;
283→              strategy: "deterministic" | "fallback";
284→            };
285→          }>,
286→          warnings: ["No Grok share turn containers found on this page."],
287→        };
288→      }
289→
290→      warnings.push(
291→        `Parsed ${turnElements.length} message candidate(s) from Grok share page.`,
292→      );
293→
294→      const messages: Array<{
295→        id: string;
296→        role: "user" | "assistant" | "unknown";
297→        rawText: string;
298→        rawHtml: string;
299→        blocks: Array<Record<string, unknown>>;
300→        parser: {
301→          source: string;
302→          blockCount: number;
303→          usedFallback: boolean;
304→          strategy: "deterministic" | "fallback";
305→        };
306→      }> = [];
307→
308→      turnElements.forEach((element, index) => {
309→        const messageId =
310→          element.getAttribute("data-message-id") ?? `grok-${index + 1}`;
311→
312→        const contentRoot = contentRootFor(element);
313→        const rawText = normalizeWhitespace(
314→          (contentRoot as HTMLElement).innerText,
315→        );
316→        const rawHtml = (contentRoot as HTMLElement).innerHTML;
317→
318→        if (!rawText) {
319→          return;
320→        }
321→
322→        const blocks = Array.from(contentRoot.childNodes).flatMap(
323→          (childNode) => {
324→            if (childNode.nodeType === Node.TEXT_NODE) {
325→              const text = normalizeWhitespace(childNode.textContent ?? "");
