347→          rawHtml,
348→          blocks: finalBlocks,
349→          parser: {
350→            source: blocks.length > 0 ? "grok-dom" : "grok-fallback",
351→            blockCount: finalBlocks.length,
352→            usedFallback: blocks.length === 0,
353→            strategy: blocks.length > 0 ? "deterministic" : "fallback",
354→          },
355→        });
356→      });
357→
358→      // Resolve unknown roles using alternating pattern
359→      if (messages.length > 0) {
