369→          }
370→        } else {
371→          // Propagate backward from first resolved role
372→          for (let i = firstResolvedIndex - 1; i >= 0; i -= 1) {
373→            const nextRole = resolvedRoles[i + 1] as "user" | "assistant";
374→            resolvedRoles[i] = nextRole === "user" ? "assistant" : "user";
375→          }
376→          // Propagate forward from first resolved role
377→          for (
378→            let i = firstResolvedIndex + 1;
379→            i < resolvedRoles.length;
380→            i += 1
