389→        let inferredCount = 0;
390→        for (let i = 0; i < messages.length; i += 1) {
391→          const msg = messages[i];
392→          const resolved = resolvedRoles[i];
393→          if (msg && msg.role === "unknown" && resolved) {
394→            inferredCount += 1;
395→            messages[i] = {
396→              ...msg,
397→              role: resolved as "user" | "assistant",
398→            };
399→          }
400→        }
401→
402→        if (inferredCount > 0) {
403→          warnings.push(
404→            `${inferredCount} message role(s) were inferred from turn order because the page did not expose explicit author markers.`,
405→          );
406→        }
407→      }
408→
409→      return {
410→        title: normalizeTitle(document.title),
411→        messages,
412→        warnings,
413→      };
414→    });
415→
416→    options?.onStage?.("normalize");
417→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
418→
419→    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
420→
421→    if (normalizedPayload.messages.length === 0) {
422→      throw new Error(
423→        "No importable messages were detected on this Grok share page.",
424→      );
425→    }
426→
427→    options?.onStage?.("structure");
428→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
429→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
430→      ...normalizedPayload,
431→      messages: structured.messages,
432→      warnings: [...normalizedPayload.warnings, ...structured.warnings],
433→      structuring: structured.structuring,
434→    });
435→    const rawHtml = await page.content();
436→    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
437→    const fetchedAt = new Date().toISOString();
438→
439→    const conversation = conversationSchema.parse({
440→      id: crypto.randomUUID(),
441→      title: finalPayload.title,
442→      source: {
443→        url,
444→        platform: "grok",
445→      },
446→      messages: finalPayload.messages,
447→    });
448→
449→    return {
450→      conversation,
451→      warnings: finalPayload.warnings,
452→      snapshot: {
453→        finalUrl: page.url(),
454→        fetchedAt,
455→        pageTitle: finalPayload.title,
456→        rawHtml,
457→        normalizedPayload: finalPayload,
458→        fetchMetadata: {
459→          articleCount: normalizedPayload.messages.length,
460→          messageCount: conversation.messages.length,
461→          rawHtmlBytes,
462→        },
463→      },
464→    };
465→  } finally {
466→    await releaseContext(context);
467→  }
468→}
