 16→/* ── Le Chat (Mistral) share-import constants ────────────── */
 17→
 18→/** Timeout for the initial page.goto() navigation. */
 19→export const PAGE_LOAD_TIMEOUT_MS = 30_000;
 20→
 21→/** Timeout for waiting until meaningful content appears in the DOM. */
 22→export const LECHAT_CONTENT_WAIT_TIMEOUT_MS = 20_000;
 23→
 24→/** Timeout for networkidle wait after DOM is ready. */
 25→export const LECHAT_NETWORK_IDLE_TIMEOUT_MS = 5_000;
 26→
 27→/** Extra delay after content appears to let the page stabilize (Le Chat is a React SPA). */
 28→export const LECHAT_PAGE_STABILIZATION_MS = 1_500;
