 76→      function normalizeTitle(rawTitle: string) {
 77→        const title = rawTitle
 78→          .replace(/\s*[-|]\s*Le Chat\s*$/i, "")
 79→          .replace(/\s*[-|]\s*Mistral\s*(AI)?\s*$/i, "")
 80→          .replace(/^Le Chat\s*[-|:]\s*/i, "")
 81→          .replace(/^Mistral\s*(AI)?\s*[-|:]\s*/i, "")
 82→          .replace(/^shared\s+/i, "")
 83→          .trim();
 84→
 85→        return title || "Untitled Chat";
 86→      }
