 99→        if (
100→          computed.display === "none" ||
101→          computed.visibility === "hidden" ||
102→          computed.opacity === "0"
103→        ) {
104→          return false;
105→        }
106→
107→        const rect = (element as HTMLElement).getBoundingClientRect();
108→        return rect.width > 0 && rect.height > 0;
109→      }
