111→      function contentRootFor(element: Element) {
112→        return (
113→          element.querySelector(
114→            ".markdown, [data-testid*='markdown'], [class*='markdown'], [class*='prose'], [data-testid*='response-content'], [data-testid*='message-content'], [data-message-content]",
115→          ) ?? element
116→        );
117→      }
