122→          element.getAttribute("data-message-author-role") ?? "",
123→          element.getAttribute("data-author-role") ?? "",
124→          element.getAttribute("data-role") ?? "",
125→          element.getAttribute("data-testid") ?? "",
126→          element.getAttribute("aria-label") ?? "",
