386→        for (let i = 0; i < messages.length; i += 1) {
387→          const msg = messages[i];
388→          const resolved = resolvedRoles[i];
389→          if (msg && msg.role === "unknown" && resolved) {
390→            inferredCount += 1;
391→            messages[i] = {
392→              ...msg,
393→              role: resolved as "user" | "assistant",
394→            };
395→          }
396→        }
397→
398→        if (inferredCount > 0) {
399→          warnings.push(
400→            `${inferredCount} message role(s) were inferred from turn order because the page did not expose explicit author markers.`,
401→          );
402→        }
403→      }
404→
405→      return {
406→        title: normalizeTitle(document.title),
407→        messages,
408→        warnings,
409→      };
410→    });
411→
412→    options?.onStage?.("normalize");
413→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
414→
415→    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
416→
417→    if (normalizedPayload.messages.length === 0) {
418→      throw new Error(
419→        "No importable messages were detected on this Le Chat share page.",
420→      );
421→    }
422→
423→    options?.onStage?.("structure");
424→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
425→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
426→      ...normalizedPayload,
427→      messages: structured.messages,
428→      warnings: [...normalizedPayload.warnings, ...structured.warnings],
429→      structuring: structured.structuring,
430→    });
431→    const rawHtml = await page.content();
432→    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
433→    const fetchedAt = new Date().toISOString();
434→
435→    const conversation = conversationSchema.parse({
436→      id: crypto.randomUUID(),
437→      title: finalPayload.title,
438→      source: {
439→        url,
440→        platform: "lechat",
441→      },
442→      messages: finalPayload.messages,
443→    });
444→
445→    return {
446→      conversation,
447→      warnings: finalPayload.warnings,
448→      snapshot: {
449→        finalUrl: page.url(),
450→        fetchedAt,
451→        pageTitle: finalPayload.title,
