  1→import {
  2→  conversationSchema,
  3→  normalizedSnapshotPayloadSchema,
  4→} from "@chat-exporter/shared";
  5→import { acquireContext, releaseContext } from "./browser-pool.js";
  6→import { MAX_MESSAGE_COUNT, MAX_RAW_HTML_BYTES } from "./constants.js";
  7→import { applyOpenAiStructuring } from "./openai-structuring.js";
  8→import {
  9→  blockNonEssentialResources,
 10→  preparePageScripts,
 11→  truncateMessagesIfNeeded,
 12→  validateRawHtmlSize,
 13→} from "./parser-page-utils.js";
 14→import type { PlatformParserResult, StageCallback } from "./parser-types.js";
 15→
 16→/* ── Perplexity share-import constants ──────────────────── */
 17→
 18→/** Timeout for the initial page.goto() navigation. */
 19→export const PAGE_LOAD_TIMEOUT_MS = 30_000;
 20→
 21→/** Timeout for waiting until meaningful content appears in the DOM. */
 22→export const PERPLEXITY_CONTENT_WAIT_TIMEOUT_MS = 20_000;
 23→
 24→/** Timeout for networkidle wait after DOM is ready. */
 25→export const PERPLEXITY_NETWORK_IDLE_TIMEOUT_MS = 5_000;
 26→
 27→/** Extra delay after content appears to let the page stabilize (Perplexity is a Next.js SPA). */
 28→export const PERPLEXITY_PAGE_STABILIZATION_MS = 1_500;
 29→
 30→/* ─────────────────────────────────────────────────────────── */
 31→
 32→export async function importPerplexitySharePage(
 33→  url: string,
 34→  options?: {
 35→    onStage?: StageCallback;
 36→  },
 37→): Promise<PlatformParserResult> {
 38→  const context = await acquireContext();
 39→
 40→  try {
 41→    await blockNonEssentialResources(context);
 42→
 43→    const page = await context.newPage();
 44→    await preparePageScripts(page);
 45→
 46→    options?.onStage?.("fetch");
 47→    await page.goto(url, {
 48→      waitUntil: "domcontentloaded",
 49→      timeout: PAGE_LOAD_TIMEOUT_MS,
 50→    });
 51→
 52→    // Perplexity is a Next.js SPA — wait for meaningful text content to render
 53→    await page
 54→      .waitForFunction(
 55→        () => {
 56→          const root =
 57→            document.querySelector("main, [role='main'], article, body") ??
 58→            document.body;
 59→          return (root.textContent ?? "").trim().length > 32;
 60→        },
 61→        { timeout: PERPLEXITY_CONTENT_WAIT_TIMEOUT_MS },
 62→      )
 63→      .catch(() => undefined);
 64→
 65→    await page
 66→      .waitForLoadState("networkidle", {
 67→        timeout: PERPLEXITY_NETWORK_IDLE_TIMEOUT_MS,
 68→      })
 69→      .catch(() => undefined);
 70→    await page.waitForTimeout(PERPLEXITY_PAGE_STABILIZATION_MS);
 71→
 72→    options?.onStage?.("extract");
 73→    const extracted = await page.evaluate(() => {
 74→      const { normalizeWhitespace, elementToBlocks } = globalThis.__domKit;
 75→
 76→      function normalizeTitle(rawTitle: string) {
 77→        const title = rawTitle
 78→          .replace(/\s*[-|]\s*Perplexity\s*$/i, "")
 79→          .replace(/^Perplexity\s*[-|:]\s*/i, "")
 80→          .replace(/\s*[-|]\s*perplexity\.ai\s*$/i, "")
 81→          .trim();
 82→
 83→        return title || "Untitled Search";
 84→      }
 85→
 86→      function isExcluded(element: Element) {
 87→        return Boolean(
 88→          element.closest(
 89→            "nav,header,footer,aside,form,dialog,[role='navigation'],[aria-hidden='true']",
 90→          ),
 91→        );
 92→      }
 93→
 94→      function isVisible(element: Element) {
 95→        const computed = globalThis.getComputedStyle(element as HTMLElement);
 96→
 97→        if (
 98→          computed.display === "none" ||
 99→          computed.visibility === "hidden" ||
100→          computed.opacity === "0"
101→        ) {
102→          return false;
103→        }
104→
105→        const rect = (element as HTMLElement).getBoundingClientRect();
106→        return rect.width > 0 && rect.height > 0;
107→      }
108→
109→      function contentRootFor(element: Element) {
110→        return (
111→          element.querySelector(
112→            ".markdown, [data-testid*='markdown'], [class*='markdown'], [class*='prose'], [data-testid*='answer'], [data-testid*='response'], [data-testid*='message-content']",
113→          ) ?? element
114→        );
115→      }
116→
117→      function attributeHintText(element: Element) {
118→        const node = element as HTMLElement;
119→        return [
120→          element.getAttribute("data-message-author-role") ?? "",
121→          element.getAttribute("data-author-role") ?? "",
122→          element.getAttribute("data-role") ?? "",
123→          element.getAttribute("data-testid") ?? "",
124→          element.getAttribute("aria-label") ?? "",
125→          node.id ?? "",
126→          typeof node.className === "string" ? node.className : "",
127→        ]
128→          .join(" ")
129→          .toLowerCase();
130→      }
131→
132→      function roleFromHints(element: Element): "user" | "assistant" | null {
133→        const hints: string[] = [];
134→        let current: Element | null = element;
135→
136→        for (let depth = 0; current && depth < 4; depth += 1) {
137→          hints.push(attributeHintText(current));
138→          current = current.parentElement;
139→        }
140→
141→        hints.push(
142→          Array.from(element.querySelectorAll("[class]"))
143→            .slice(0, 24)
144→            .map((node) => ((node as HTMLElement).className || "").toString())
145→            .join(" ")
146→            .toLowerCase(),
147→        );
148→
149→        const hintText = hints.join(" ");
150→
151→        // Perplexity-specific: questions/queries are user turns
152→        if (
153→          /(^|\b)(user|human|prompt|question|query|search|from-user|self-end|justify-end|ml-auto|text-right)(\b|$)/.test(
154→            hintText,
155→          )
156→        ) {
157→          return "user";
158→        }
159→
160→        // Perplexity-specific: answers with sources/citations are assistant turns
161→        if (
162→          /(^|\b)(assistant|model|bot|perplexity|response|answer|result|citation|source|self-start|justify-start|mr-auto|text-left|prose|markdown)(\b|$)/.test(
163→            hintText,
164→          )
165→        ) {
166→          return "assistant";
167→        }
168→
169→        return null;
170→      }
171→
172→      const warnings: string[] = [];
173→
174→      // Strategy 1: Look for explicit Perplexity turn/message containers
175→      // Perplexity uses data attributes and class-based selectors
176→      const turnSelectors = [
177→        "[data-testid*='conversation-turn']",
178→        "[data-testid*='chat-turn']",
179→        "[data-testid*='message']",
180→        "[data-testid*='query']",
181→        "[data-testid*='answer']",
182→        "[data-message-id]",
183→        "[data-message-author-role]",
184→      ];
185→
186→      let turnElements: Element[] = [];
187→      for (const selector of turnSelectors) {
188→        const found = Array.from(document.querySelectorAll(selector)).filter(
189→          (el) => isVisible(el) && !isExcluded(el),
190→        );
191→        if (found.length >= 2) {
192→          turnElements = found;
193→          break;
194→        }
195→      }
196→
197→      // Strategy 2: Look for Q&A pair containers common in Perplexity
198→      if (turnElements.length < 2) {
199→        const roleContainers = Array.from(
200→          document.querySelectorAll(
201→            "[class*='message'], [class*='turn'], [class*='query'], [class*='answer'], [class*='response'], [class*='question'], [class*='prompt'], [class*='result']",
202→          ),
203→        ).filter((el) => {
204→          if (!isVisible(el) || isExcluded(el)) return false;
205→          const text = normalizeWhitespace((el as HTMLElement).innerText);
206→          return text.length > 2;
207→        });
208→
209→        if (roleContainers.length >= 2) {
210→          turnElements = roleContainers;
211→        }
212→      }
213→
214→      // Strategy 3: Container heuristic — find main content area and extract children
215→      if (turnElements.length < 2) {
216→        const mainContent =
217→          document.querySelector("main") ??
218→          document.querySelector("[role='main']") ??
219→          document.querySelector("article") ??
220→          document.body;
221→
222→        const candidates = Array.from(
223→          mainContent.querySelectorAll("div,section,article"),
224→        ).filter((el) => {
225→          if (!isVisible(el) || isExcluded(el)) return false;
226→          const children = Array.from(el.children).filter(
227→            (child) =>
228→              isVisible(child) &&
229→              !isExcluded(child) &&
230→              normalizeWhitespace((child as HTMLElement).innerText).length > 10,
231→          );
232→          return children.length >= 2;
233→        });
234→
235→        let bestContainer: Element | null = null;
236→        let bestChildCount = 0;
237→
238→        for (const candidate of candidates.slice(0, 100)) {
239→          const children = Array.from(candidate.children).filter((child) => {
240→            if (!isVisible(child) || isExcluded(child)) return false;
241→            const text = normalizeWhitespace((child as HTMLElement).innerText);
242→            return text.length > 10;
243→          });
244→
245→          const hintedCount = children.filter((child) =>
246→            /(message|turn|query|answer|question|response|prompt|result|perplexity|assistant|user|human)/i.test(
247→              attributeHintText(child),
248→            ),
249→          ).length;
250→
251→          const score = children.length + hintedCount * 2;
252→          if (score > bestChildCount && children.length >= 2) {
253→            bestChildCount = score;
254→            bestContainer = candidate;
255→          }
256→        }
257→
258→        if (bestContainer) {
259→          turnElements = Array.from(bestContainer.children).filter(
260→            (child) =>
261→              isVisible(child) &&
262→              !isExcluded(child) &&
263→              normalizeWhitespace((child as HTMLElement).innerText).length > 2,
264→          );
265→        }
266→      }
267→
268→      if (turnElements.length === 0) {
269→        return {
270→          title: normalizeTitle(document.title),
271→          messages: [] as Array<{
272→            id: string;
273→            role: "user" | "assistant" | "unknown";
274→            rawText: string;
275→            rawHtml: string;
276→            blocks: Array<Record<string, unknown>>;
277→            parser: {
278→              source: string;
279→              blockCount: number;
280→              usedFallback: boolean;
281→              strategy: "deterministic" | "fallback";
282→            };
283→          }>,
284→          warnings: ["No Perplexity share turn containers found on this page."],
285→        };
286→      }
287→
288→      warnings.push(
289→        `Parsed ${turnElements.length} message candidate(s) from Perplexity share page.`,
290→      );
291→
292→      const messages: Array<{
293→        id: string;
294→        role: "user" | "assistant" | "unknown";
295→        rawText: string;
296→        rawHtml: string;
297→        blocks: Array<Record<string, unknown>>;
298→        parser: {
299→          source: string;
300→          blockCount: number;
301→          usedFallback: boolean;
302→          strategy: "deterministic" | "fallback";
303→        };
304→      }> = [];
305→
306→      turnElements.forEach((element, index) => {
307→        const messageId =
308→          element.getAttribute("data-message-id") ?? `perplexity-${index + 1}`;
309→
310→        const contentRoot = contentRootFor(element);
311→        const rawText = normalizeWhitespace(
312→          (contentRoot as HTMLElement).innerText,
313→        );
314→        const rawHtml = (contentRoot as HTMLElement).innerHTML;
315→
316→        if (!rawText) {
317→          return;
318→        }
319→
320→        const blocks = Array.from(contentRoot.childNodes).flatMap(
321→          (childNode) => {
322→            if (childNode.nodeType === Node.TEXT_NODE) {
323→              const text = normalizeWhitespace(childNode.textContent ?? "");
324→              return text ? [{ type: "paragraph" as const, text }] : [];
325→            }
326→
327→            if (childNode.nodeType !== Node.ELEMENT_NODE) {
328→              return [];
329→            }
330→
331→            return elementToBlocks(childNode as Element);
332→          },
333→        );
334→
335→        const hintedRole = roleFromHints(element);
336→        const finalBlocks =
337→          blocks.length > 0
338→            ? blocks
339→            : [{ type: "paragraph" as const, text: rawText }];
340→
341→        messages.push({
342→          id: messageId,
343→          role: hintedRole ?? "unknown",
344→          rawText,
345→          rawHtml,
346→          blocks: finalBlocks,
347→          parser: {
348→            source:
349→              blocks.length > 0 ? "perplexity-dom" : "perplexity-fallback",
350→            blockCount: finalBlocks.length,
351→            usedFallback: blocks.length === 0,
352→            strategy: blocks.length > 0 ? "deterministic" : "fallback",
353→          },
354→        });
355→      });
356→
357→      // Resolve unknown roles using alternating pattern
358→      if (messages.length > 0) {
359→        const resolvedRoles = messages.map((m) =>
360→          m.role === "unknown" ? null : m.role,
361→        );
362→        const firstResolvedIndex = resolvedRoles.findIndex(Boolean);
363→
364→        if (firstResolvedIndex === -1) {
365→          // No roles detected — assume alternating user/assistant
366→          for (let i = 0; i < resolvedRoles.length; i += 1) {
367→            resolvedRoles[i] = i % 2 === 0 ? "user" : "assistant";
368→          }
369→        } else {
370→          // Propagate backward from first resolved role
371→          for (let i = firstResolvedIndex - 1; i >= 0; i -= 1) {
372→            const nextRole = resolvedRoles[i + 1] as "user" | "assistant";
373→            resolvedRoles[i] = nextRole === "user" ? "assistant" : "user";
374→          }
375→          // Propagate forward from first resolved role
376→          for (
377→            let i = firstResolvedIndex + 1;
378→            i < resolvedRoles.length;
379→            i += 1
380→          ) {
381→            if (!resolvedRoles[i]) {
382→              const prevRole = resolvedRoles[i - 1] as "user" | "assistant";
383→              resolvedRoles[i] = prevRole === "user" ? "assistant" : "user";
384→            }
385→          }
386→        }
387→
388→        let inferredCount = 0;
389→        for (let i = 0; i < messages.length; i += 1) {
390→          const msg = messages[i];
391→          const resolved = resolvedRoles[i];
392→          if (msg && msg.role === "unknown" && resolved) {
393→            inferredCount += 1;
394→            messages[i] = {
395→              ...msg,
396→              role: resolved as "user" | "assistant",
397→            };
398→          }
399→        }
400→
401→        if (inferredCount > 0) {
402→          warnings.push(
403→            `${inferredCount} message role(s) were inferred from turn order because the page did not expose explicit author markers.`,
404→          );
405→        }
406→      }
407→
408→      return {
409→        title: normalizeTitle(document.title),
410→        messages,
411→        warnings,
412→      };
413→    });
414→
415→    options?.onStage?.("normalize");
416→    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
417→
418→    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
419→
420→    if (normalizedPayload.messages.length === 0) {
421→      throw new Error(
422→        "No importable messages were detected on this Perplexity share page.",
423→      );
424→    }
425→
426→    options?.onStage?.("structure");
427→    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
428→    const finalPayload = normalizedSnapshotPayloadSchema.parse({
429→      ...normalizedPayload,
430→      messages: structured.messages,
431→      warnings: [...normalizedPayload.warnings, ...structured.warnings],
432→      structuring: structured.structuring,
433→    });
434→    const rawHtml = await page.content();
435→    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
436→    const fetchedAt = new Date().toISOString();
437→
438→    const conversation = conversationSchema.parse({
439→      id: crypto.randomUUID(),
440→      title: finalPayload.title,
441→      source: {
442→        url,
443→        platform: "perplexity",
444→      },
445→      messages: finalPayload.messages,
446→    });
447→
448→    return {
449→      conversation,
450→      warnings: finalPayload.warnings,
451→      snapshot: {
452→        finalUrl: page.url(),
453→        fetchedAt,
454→        pageTitle: finalPayload.title,
455→        rawHtml,
456→        normalizedPayload: finalPayload,
457→        fetchMetadata: {
458→          articleCount: normalizedPayload.messages.length,
459→          messageCount: conversation.messages.length,
460→          rawHtmlBytes,
461→        },
462→      },
463→    };
464→  } finally {
465→    await releaseContext(context);
466→  }
467→}
