 1→import type { SourcePlatform } from "@chat-exporter/shared";
 2→
 3→function normalizeHostname(hostname: string) {
 4→  return hostname.toLowerCase().replace(/^www\./, "");
 5→}
 6→
 7→export function hasSupportedImportProtocol(urlString: string) {
 8→  const url = new URL(urlString);
 9→  return url.protocol === "https:" || url.protocol === "http:";
10→}
11→
12→export function classifySourcePlatform(urlString: string): SourcePlatform {
13→  const url = new URL(urlString);
14→  const hostname = normalizeHostname(url.hostname);
15→  const pathname = url.pathname.toLowerCase();
16→
17→  if (
18→    hostname === "chatgpt.com" ||
19→    hostname.endsWith(".chatgpt.com") ||
20→    hostname === "chat.openai.com"
21→  ) {
22→    return "chatgpt";
23→  }
24→
25→  if (hostname === "claude.ai" || hostname.endsWith(".claude.ai")) {
26→    return "claude";
27→  }
28→
29→  if (
30→    hostname === "gemini.google.com" ||
31→    hostname.endsWith(".gemini.google.com") ||
32→    (hostname === "g.co" && pathname.startsWith("/gemini"))
33→  ) {
34→    return "gemini";
35→  }
36→
37→  if (
38→    hostname === "grok.com" ||
39→    hostname.endsWith(".grok.com") ||
40→    (hostname === "x.com" && pathname.includes("/grok"))
41→  ) {
42→    return "grok";
43→  }
44→
45→  if (hostname.includes("deepseek")) {
46→    return "deepseek";
47→  }
48→
49→  if (hostname.includes("notebooklm")) {
50→    return "notebooklm";
51→  }
52→
53→  if (
54→    hostname === "aistudio.google.com" ||
55→    hostname.endsWith(".aistudio.google.com")
56→  ) {
57→    return "aistudio";
58→  }
59→
60→  if (hostname === "perplexity.ai" || hostname.endsWith(".perplexity.ai")) {
61→    return "perplexity";
62→  }
63→
64→  if (hostname === "chat.mistral.ai" || hostname.endsWith(".mistral.ai")) {
65→    return "lechat";
66→  }
67→
68→  if (hostname === "kimi.moonshot.cn" || hostname.endsWith(".moonshot.cn")) {
69→    return "kimi";
70→  }
71→
72→  return "unknown";
73→}
