 15→function serializeImport(job: ImportJob) {
 16→  return {
 17→    id: job.id,
 18→    sourceUrl: job.sourceUrl,
 19→    sourcePlatform: job.sourcePlatform,
 20→    mode: job.mode,
 21→    importMethod: job.importMethod,
 22→    status: job.status,
 23→    currentStage: job.currentStage,
 24→    createdAt: job.createdAt,
 25→    updatedAt: job.updatedAt,
 26→    warningsJson: JSON.stringify(job.warnings),
 27→    error: job.error ?? null,
 28→    errorStage: job.errorStage ?? null,
 29→    summaryJson: job.summary ? JSON.stringify(job.summary) : null,
 30→    conversationJson: job.conversation
 31→      ? JSON.stringify(job.conversation)
 32→      : null,
 33→    artifactsJson: job.artifacts ? JSON.stringify(job.artifacts) : null,
 34→  };
 35→}
 36→
 37→function parseJson<T>(value: string | null): T | undefined {
 38→  if (!value) {
 39→    return undefined;
 40→  }
 41→
 42→  return JSON.parse(value) as T;
 43→}
 44→
 45→function deserializeImport(row: Import) {
 46→  return importJobSchema.parse({
 47→    id: row.id,
 48→    sourceUrl: row.sourceUrl,
 49→    sourcePlatform: row.sourcePlatform,
 50→    mode: row.mode,
 51→    importMethod: row.importMethod,
 52→    status: row.status,
 53→    currentStage: row.currentStage,
 54→    createdAt: row.createdAt,
 55→    updatedAt: row.updatedAt,
 56→    warnings: parseJson<string[]>(row.warningsJson) ?? [],
 57→    error: row.error ?? undefined,
 58→    errorStage: row.errorStage ?? undefined,
 59→    summary: parseJson<ImportJob["summary"]>(row.summaryJson),
 60→    conversation: parseJson<Conversation>(row.conversationJson),
 61→    artifacts: parseJson<ImportArtifacts>(row.artifactsJson),
 62→  });
 63→}
 64→
 65→export function insertImport(job: ImportJob) {
 66→  db.insert(imports).values(serializeImport(job)).run();
 67→}
 68→
 69→export function replaceImport(job: ImportJob) {
 70→  const data = serializeImport(job);
 71→  const { id: _id, ...fields } = data;
 72→  db.update(imports).set(fields).where(eq(imports.id, job.id)).run();
 73→}
 74→
 75→export function getPersistedImport(id: string) {
 76→  const row = db.select().from(imports).where(eq(imports.id, id)).get();
 77→  return row ? deserializeImport(row) : undefined;
 78→}
