 89→export function saveImportSnapshot(input: {
 90→  importId: string;
 91→  sourceUrl: string;
 92→  finalUrl: string;
 93→  fetchedAt: string;
 94→  pageTitle: string;
 95→  rawHtml: string;
 96→  normalizedPayload: unknown;
 97→  fetchMetadata: Record<string, unknown>;
 98→}) {
 99→  const data = {
100→    importId: input.importId,
101→    sourceUrl: input.sourceUrl,
102→    finalUrl: input.finalUrl,
103→    fetchedAt: input.fetchedAt,
104→    pageTitle: input.pageTitle,
105→    rawHtml: input.rawHtml,
106→    normalizedPayloadJson: JSON.stringify(input.normalizedPayload),
107→    fetchMetadataJson: JSON.stringify(input.fetchMetadata),
108→    updatedAt: input.fetchedAt,
109→  };
110→
111→  db.insert(importSnapshots)
112→    .values(data)
113→    .onConflictDoUpdate({
114→      target: importSnapshots.importId,
115→      set: {
116→        sourceUrl: data.sourceUrl,
117→        finalUrl: data.finalUrl,
118→        fetchedAt: data.fetchedAt,
119→        pageTitle: data.pageTitle,
120→        rawHtml: data.rawHtml,
121→        normalizedPayloadJson: data.normalizedPayloadJson,
122→        fetchMetadataJson: data.fetchMetadataJson,
123→        updatedAt: data.updatedAt,
124→      },
125→    })
126→    .run();
127→}
