129→export function listImportSummaries(
130→  params?: Partial<ImportListRequest>,
131→): ImportSummary[] {
132→  const sortBy = params?.sortBy ?? "createdAt";
133→  const sortOrder = params?.sortOrder ?? "desc";
134→
135→  const columnMap = {
136→    createdAt: imports.createdAt,
137→    updatedAt: imports.updatedAt,
138→    sourcePlatform: imports.sourcePlatform,
139→    status: imports.status,
140→  } as const;
141→
142→  const orderColumn = columnMap[sortBy];
143→  const orderFn = sortOrder === "asc" ? asc : desc;
144→
145→  let query = db
146→    .select({
147→      id: imports.id,
148→      sourceUrl: imports.sourceUrl,
149→      sourcePlatform: imports.sourcePlatform,
150→      mode: imports.mode,
151→      importMethod: imports.importMethod,
152→      status: imports.status,
153→      currentStage: imports.currentStage,
154→      createdAt: imports.createdAt,
155→      updatedAt: imports.updatedAt,
156→      warningsJson: imports.warningsJson,
157→      error: imports.error,
158→      summaryJson: imports.summaryJson,
159→      pageTitle: importSnapshots.pageTitle,
160→    })
161→    .from(imports)
162→    .leftJoin(importSnapshots, eq(imports.id, importSnapshots.importId))
163→    .orderBy(orderFn(orderColumn))
164→    .$dynamic();
165→
166→  const conditions = [];
167→
168→  if (params?.status) {
169→    conditions.push(eq(imports.status, params.status));
170→  }
171→
172→  if (params?.platform) {
173→    conditions.push(eq(imports.sourcePlatform, params.platform));
174→  }
175→
176→  if (params?.search) {
177→    const pattern = `%${params.search}%`;
178→    conditions.push(
179→      or(
180→        like(imports.sourceUrl, pattern),
181→        like(importSnapshots.pageTitle, pattern),
182→      ),
183→    );
184→  }
185→
186→  if (conditions.length > 0) {
187→    query = query.where(and(...conditions));
188→  }
189→
190→  return query.all().flatMap((row) => {
191→    const parsed = importSummarySchema.safeParse({
192→      id: row.id,
193→      sourceUrl: row.sourceUrl,
194→      sourcePlatform: row.sourcePlatform,
195→      mode: row.mode,
196→      importMethod: row.importMethod,
197→      status: row.status,
198→      currentStage: row.currentStage,
199→      createdAt: row.createdAt,
200→      updatedAt: row.updatedAt,
201→      warnings: parseJson<string[]>(row.warningsJson) ?? [],
202→      error: row.error ?? undefined,
203→      summary: parseJson<ImportJob["summary"]>(row.summaryJson),
204→      pageTitle: row.pageTitle ?? undefined,
205→    });
206→    return parsed.success ? [parsed.data] : [];
207→  });
208→}
