  9→export type ClipboardImportResult = {
 10→  conversation: Conversation;
 11→  warnings: string[];
 12→  detectedPlatform: SourcePlatform;
 13→};
 14→
 15→/**
 16→ * Import a conversation from clipboard content (HTML and/or plain text).
 17→ * No browser required — uses JSDOM for HTML parsing.
 18→ */
 19→export async function importFromClipboard(input: {
 20→  html?: string;
 21→  plainText?: string;
 22→}): Promise<ClipboardImportResult> {
 23→  const warnings: string[] = [];
 24→
 25→  if (input.html) {
 26→    return importFromClipboardHtml(input.html, warnings);
 27→  }
 28→
 29→  if (input.plainText) {
 30→    return importFromClipboardText(input.plainText, warnings);
 31→  }
 32→
 33→  throw new Error("Either html or plainText must be provided");
 34→}
 35→
 36→// ---------------------------------------------------------------------------
 37→// Platform detection
 38→// ---------------------------------------------------------------------------
 39→
 40→export function detectPlatformFromHtml(html: string): SourcePlatform {
 41→  const lower = html.toLowerCase();
 42→
 43→  if (lower.includes("data-message-author-role")) return "chatgpt";
 44→  if (lower.includes("font-claude-message") || lower.includes("claude.ai"))
 45→    return "claude";
 46→  if (lower.includes("share-turn-viewer") || lower.includes("gemini"))
 47→    return "gemini";
 48→  if (lower.includes("grok")) return "grok";
 49→  if (lower.includes("deepseek")) return "deepseek";
 50→  if (lower.includes("perplexity")) return "perplexity";
 51→  if (lower.includes("mistral") || lower.includes("lechat")) return "lechat";
 52→
 53→  return "unknown";
 54→}
 55→
 56→// ---------------------------------------------------------------------------
 57→// HTML path
 58→// ---------------------------------------------------------------------------
 59→
 60→function importFromClipboardHtml(
 61→  html: string,
 62→  warnings: string[],
 63→): ClipboardImportResult {
 64→  const platform = detectPlatformFromHtml(html);
 65→
 66→  if (platform === "unknown") {
 67→    warnings.push("Could not detect platform from clipboard HTML");
 68→  }
 69→
 70→  const dom = new JSDOM(html, { runScripts: "outside-only" });
 71→  const { window } = dom;
 72→
 73→  // Inject DOM kit helpers via eval — "outside-only" prevents user-supplied
 74→  // scripts from executing while allowing programmatic injection.
 75→  window.eval(DOM_KIT_SCRIPT);
 76→
 77→  // biome-ignore lint/suspicious/noExplicitAny: JSDOM global access requires dynamic typing
 78→  const domKit = (window as any).__domKit as
 79→    | {
 80→        elementToBlocks: (el: Element) => Array<Record<string, unknown>>;
 81→      }
 82→    | undefined;
 83→
 84→  if (!domKit) {
 85→    warnings.push("DOM kit injection failed, falling back to basic extraction");
 86→    const text = window.document.body?.textContent?.trim() ?? "";
 87→    window.close();
 88→    return createSingleMessageResult(text, platform, warnings);
 89→  }
 90→
 91→  const messages = extractMessagesFromDom(
 92→    window.document,
 93→    domKit,
 94→    platform,
 95→    warnings,
 96→  );
 97→
 98→  const title = extractTitleFromDom(window.document, platform) || "Pasted Chat";
 99→
100→  window.close();
101→
102→  if (messages.length === 0) {
103→    warnings.push("No messages found in clipboard HTML");
104→    const text = html
105→      .replace(/<[^>]*>/g, " ")
106→      .replace(/\s+/g, " ")
107→      .trim();
108→    return createSingleMessageResult(text, platform, warnings);
109→  }
110→
111→  const conversation = conversationSchema.parse({
112→    id: crypto.randomUUID(),
113→    title,
114→    source: { url: "clipboard://paste", platform },
115→    messages,
116→  });
117→
118→  return { conversation, warnings, detectedPlatform: platform };
119→}
