121→// ---------------------------------------------------------------------------
122→// DOM message extraction
123→// ---------------------------------------------------------------------------
124→
125→function extractMessagesFromDom(
126→  document: Document,
127→  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
128→  platform: SourcePlatform,
129→  warnings: string[],
130→): Array<{
131→  id: string;
132→  role: string;
133→  blocks: Array<Record<string, unknown>>;
134→}> {
135→  // Try platform-specific extraction
136→  const platformMessages = extractPlatformSpecific(
137→    document,
138→    domKit,
139→    platform,
140→    warnings,
141→  );
142→  if (platformMessages.length > 0) return platformMessages;
143→
144→  if (platform !== "unknown") {
145→    warnings.push(
146→      `Detected ${platform} but could not extract messages, falling back to generic extraction`,
147→    );
148→  }
149→
150→  // Generic: treat the entire body as a single assistant message
151→  return extractGeneric(document, domKit);
152→}
153→
154→function extractPlatformSpecific(
155→  document: Document,
156→  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
157→  platform: SourcePlatform,
158→  _warnings: string[],
159→): Array<{
160→  id: string;
161→  role: string;
162→  blocks: Array<Record<string, unknown>>;
163→}> {
164→  const messages: Array<{
165→    id: string;
166→    role: string;
167→    blocks: Array<Record<string, unknown>>;
168→  }> = [];
169→
170→  if (platform === "chatgpt") {
171→    // ChatGPT uses data-message-author-role attribute
172→    const turns = document.querySelectorAll("[data-message-author-role]");
173→    for (const turn of turns) {
174→      const role =
175→        turn.getAttribute("data-message-author-role") === "user"
176→          ? "user"
177→          : "assistant";
178→      const blocks = domKit.elementToBlocks(turn as Element);
179→      if (blocks.length > 0) {
180→        messages.push({ id: crypto.randomUUID(), role, blocks });
181→      }
182→    }
183→  }
184→
185→  // Additional platform-specific selectors can be added here
186→
187→  return messages;
188→}
189→
190→function extractGeneric(
191→  document: Document,
192→  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
193→): Array<{
194→  id: string;
195→  role: string;
196→  blocks: Array<Record<string, unknown>>;
197→}> {
198→  const body = document.body;
199→  if (!body) return [];
200→
201→  const blocks = domKit.elementToBlocks(body);
202→  if (blocks.length === 0) return [];
203→
204→  return [
205→    {
206→      id: crypto.randomUUID(),
207→      role: "unknown",
208→      blocks,
209→    },
210→  ];
211→}
212→
213→function extractTitleFromDom(
214→  document: Document,
215→  _platform: SourcePlatform,
216→): string | null {
217→  // Try <title> first
218→  const title = document.querySelector("title")?.textContent?.trim();
219→  if (title) return title;
220→
221→  // Try first <h1>
222→  const h1 = document.querySelector("h1")?.textContent?.trim();
223→  if (h1) return h1;
224→
225→  return null;
226→}
227→
228→// ---------------------------------------------------------------------------
229→// Plain-text path
230→// ---------------------------------------------------------------------------
231→
232→const ROLE_HEADERS: Record<string, "user" | "assistant"> = {
233→  you: "user",
234→  user: "user",
235→  human: "user",
236→  claude: "assistant",
237→  chatgpt: "assistant",
238→  assistant: "assistant",
239→  grok: "assistant",
240→  gemini: "assistant",
241→  deepseek: "assistant",
242→  perplexity: "assistant",
243→};
244→
245→const PLATFORM_FROM_HEADER: Record<string, SourcePlatform> = {
246→  claude: "claude",
247→  chatgpt: "chatgpt",
248→  grok: "grok",
249→  gemini: "gemini",
250→  deepseek: "deepseek",
251→  perplexity: "perplexity",
252→};
253→
254→function importFromClipboardText(
255→  text: string,
256→  warnings: string[],
257→): ClipboardImportResult {
258→  const lines = text.split("\n");
259→  const messages: Array<{
260→    id: string;
261→    role: string;
262→    blocks: Array<{ type: string; text: string }>;
263→  }> = [];
264→  let currentRole: "user" | "assistant" | null = null;
265→  let currentContent: string[] = [];
266→  let detectedPlatform: SourcePlatform = "unknown";
267→
268→  for (const line of lines) {
269→    const trimmed = line.trim();
270→    const normalizedHeader = trimmed.toLowerCase().replace(/:$/, "");
271→    const headerRole = ROLE_HEADERS[normalizedHeader];
272→
273→    if (headerRole) {
274→      // Flush previous message
275→      if (currentRole && currentContent.length > 0) {
276→        const content = currentContent.join("\n").trim();
277→        if (content) {
278→          messages.push({
279→            id: crypto.randomUUID(),
280→            role: currentRole,
281→            blocks: [{ type: "paragraph", text: content }],
282→          });
283→        }
284→      }
285→      currentRole = headerRole;
286→      currentContent = [];
287→
288→      // Detect platform from header
289→      if (
290→        detectedPlatform === "unknown" &&
291→        PLATFORM_FROM_HEADER[normalizedHeader]
292→      ) {
293→        detectedPlatform = PLATFORM_FROM_HEADER[normalizedHeader];
294→      }
295→    } else {
296→      currentContent.push(line);
297→    }
298→  }
299→
300→  // Flush last message
301→  if (currentRole && currentContent.length > 0) {
302→    const content = currentContent.join("\n").trim();
303→    if (content) {
304→      messages.push({
305→        id: crypto.randomUUID(),
306→        role: currentRole,
307→        blocks: [{ type: "paragraph", text: content }],
308→      });
309→    }
310→  }
311→
312→  if (messages.length === 0) {
313→    warnings.push(
314→      "No role headers found in plain text. Creating single message.",
315→    );
316→    messages.push({
317→      id: crypto.randomUUID(),
318→      role: "unknown",
319→      blocks: [{ type: "paragraph", text: text.trim() }],
320→    });
321→  }
322→
323→  warnings.push("Imported from plain text — formatting may be lost.");
324→
325→  const conversation = conversationSchema.parse({
326→    id: crypto.randomUUID(),
327→    title: "Pasted Chat",
328→    source: { url: "clipboard://paste", platform: detectedPlatform },
329→    messages,
330→  });
331→
332→  return {
333→    conversation,
334→    warnings,
335→    detectedPlatform,
336→  };
337→}
338→
339→// ---------------------------------------------------------------------------
340→// Helpers
341→// ---------------------------------------------------------------------------
342→
343→function createSingleMessageResult(
344→  text: string,
345→  platform: SourcePlatform,
346→  warnings: string[],
347→): ClipboardImportResult {
348→  const conversation = conversationSchema.parse({
349→    id: crypto.randomUUID(),
350→    title: "Pasted Chat",
351→    source: { url: "clipboard://paste", platform },
352→    messages: [
353→      {
354→        id: crypto.randomUUID(),
355→        role: "unknown",
356→        blocks: text ? [{ type: "paragraph", text }] : [],
357→      },
358→    ],
359→  });
360→
361→  return { conversation, warnings, detectedPlatform: platform };
362→}
