411→// ---------------------------------------------------------------------------
412→// Context Builder
413→// ---------------------------------------------------------------------------
414→
415→function blockToPlainText(block: Block) {
416→  switch (block.type) {
417→    case "paragraph":
418→    case "heading":
419→    case "quote":
420→    case "code":
421→      return block.text;
422→    case "list":
423→      return block.items.join("\n");
424→    case "table":
425→      return [
426→        block.headers.join(" | "),
427→        ...block.rows.map((row) => row.join(" | ")),
428→      ].join("\n");
429→  }
430→}
431→
432→function summarizeSelection(
433→  sessionDetail: AdjustmentSessionDetail,
434→  job: ImportJob | undefined,
435→) {
436→  const { selection, targetFormat } = sessionDetail.session;
437→
438→  if (targetFormat === "markdown") {
439→    const markdown = job?.artifacts?.markdown ?? "";
440→    const lines = markdown.split("\n");
441→    const lineStart = selection.lineStart ?? 1;
442→    const lineEnd = selection.lineEnd ?? lineStart;
443→
444→    return {
445→      currentExcerpt:
446→        lines.slice(lineStart - 1, lineEnd).join("\n") ||
447→        selection.selectedText,
448→      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
449→      surrounding: {
450→        next: lines[lineEnd] ?? null,
451→        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
452→      },
453→    };
454→  }
455→
456→  const message = job?.conversation?.messages.find(
457→    (entry) => entry.id === selection.messageId,
458→  );
459→  const currentBlock = message?.blocks[selection.blockIndex];
460→  const previousBlock =
461→    selection.blockIndex > 0
462→      ? message?.blocks[selection.blockIndex - 1]
463→      : undefined;
464→  const nextBlock = message?.blocks[selection.blockIndex + 1];
465→
466→  return {
467→    currentExcerpt: currentBlock
468→      ? blockToPlainText(currentBlock)
469→      : selection.selectedText,
470→    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
471→    surrounding: {
472→      next: nextBlock ? blockToPlainText(nextBlock) : null,
473→      previous: previousBlock ? blockToPlainText(previousBlock) : null,
474→    },
475→  };
476→}
477→
478→function buildSelectionContext(input: RunAgentTurnInput) {
479→  const { activeRules, job, sessionDetail } = input;
480→  const { selection, targetFormat } = sessionDetail.session;
481→  const selectionContext = summarizeSelection(sessionDetail, job);
482→  const lines: string[] = [];
483→
484→  lines.push("## Ausgewählter Block");
485→  lines.push(`Format: ${targetFormat}`);
486→  lines.push(
487→    `Block: ${selection.blockType} (messageId: "${selection.messageId}", blockId: "${selection.blockId ?? ""}", blockIndex: ${selection.blockIndex})`,
488→  );
489→  lines.push(
490→    `Rolle: ${selection.messageRole}, Nachricht ${selection.messageIndex + 1}`,
491→  );
492→  if (selection.lineStart != null) {
493→    lines.push(
494→      `Zeilen: ${selection.lineStart}-${selection.lineEnd ?? selection.lineStart}`,
495→    );
496→  }
497→  lines.push("");
498→  lines.push("Inhalt des ausgewählten Blocks:");
499→  lines.push("```");
500→  lines.push(selectionContext.currentExcerpt);
501→  lines.push("```");
502→
503→  if (selectionContext.surrounding.previous) {
504→    lines.push("");
505→    lines.push("Block davor:");
506→    lines.push(`> ${selectionContext.surrounding.previous.slice(0, 200)}`);
507→  }
508→  if (selectionContext.surrounding.next) {
509→    lines.push("");
510→    lines.push("Block danach:");
511→    lines.push(`> ${selectionContext.surrounding.next.slice(0, 200)}`);
512→  }
513→
514→  const active = activeRules
515→    .filter((rule) => rule.status === "active")
516→    .slice(0, 8);
517→  if (active.length > 0) {
518→    lines.push("");
519→    lines.push("## Bereits aktive Regeln");
520→    for (const rule of active) {
521→      const selectorStr = rule.selector
522→        ? JSON.stringify(rule.selector)
523→        : "(kein Selektor)";
524→      lines.push(
525→        `- [${rule.id}] ${rule.instruction ?? "(keine Beschreibung)"} — Selektor: ${selectorStr}`,
526→      );
527→    }
528→  }
529→
530→  return lines.join("\n");
531→}
532→
533→type InputMessage = {
534→  content: Array<{ text: string; type: "input_text" | "output_text" }>;
535→  role: "system" | "user" | "assistant";
536→};
537→
538→function buildInputMessages(input: RunAgentTurnInput): InputMessage[] {
539→  const targetFormat = input.sessionDetail.session.targetFormat;
540→  const messages: InputMessage[] = [
541→    {
542→      content: [{ text: buildSystemPrompt(targetFormat), type: "input_text" }],
543→      role: "system",
544→    },
545→    {
546→      content: [{ text: buildSelectionContext(input), type: "input_text" }],
547→      role: "user",
548→    },
549→  ];
550→
551→  // Add session messages as real multi-turn conversation so the model
552→  // understands the full dialog history and can reference prior turns.
553→  for (const msg of input.sessionDetail.messages) {
554→    const role = msg.role === "user" ? "user" : "assistant";
555→    messages.push({
556→      content: [
557→        {
558→          text: msg.content,
559→          type: role === "assistant" ? "output_text" : "input_text",
560→        },
561→      ],
562→      role,
563→    });
564→  }
565→
566→  return messages;
567→}
568→
569→// ---------------------------------------------------------------------------
570→// OpenAI helpers
571→// ---------------------------------------------------------------------------
572→
573→function isRecord(value: unknown): value is Record<string, unknown> {
574→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
575→}
576→
577→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
578→  if (!Array.isArray(payload.output)) {
579→    return [];
580→  }
581→
582→  return payload.output.flatMap((item) => {
583→    if (!isRecord(item) || item.type !== "function_call") {
584→      return [];
585→    }
586→
587→    const callId = typeof item.call_id === "string" ? item.call_id : null;
588→    const name = typeof item.name === "string" ? item.name : null;
589→    const args = typeof item.arguments === "string" ? item.arguments : null;
590→
591→    if (!callId || !name || !args) {
592→      return [];
593→    }
594→
595→    return [{ arguments: args, callId, name }];
596→  });
597→}
598→
599→function extractAssistantMessage(payload: ResponsesPayload) {
600→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
601→    return payload.output_text.trim();
602→  }
603→
604→  if (!Array.isArray(payload.output)) {
605→    return "";
606→  }
607→
608→  return payload.output
609→    .flatMap((item) => {
610→      if (
611→        !isRecord(item) ||
612→        item.type !== "message" ||
613→        item.role !== "assistant"
614→      ) {
615→        return [];
616→      }
617→
618→      const content = item.content;
619→      if (!Array.isArray(content)) {
620→        return [];
621→      }
622→
623→      return content.flatMap((entry) => {
624→        if (!isRecord(entry) || entry.type !== "output_text") {
625→          return [];
626→        }
627→
628→        return typeof entry.text === "string" && entry.text.trim()
629→          ? [entry.text.trim()]
630→          : [];
631→      });
632→    })
633→    .join("\n")
634→    .trim();
635→}
636→
637→async function requestOpenAiResponse(
638→  body: Record<string, unknown>,
639→  config: ReturnType<typeof readAdjustmentAiConfig>,
640→) {
641→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
642→    method: "POST",
643→    headers: {
644→      "Content-Type": "application/json",
645→      Authorization: `Bearer ${config.openai?.apiKey}`,
646→    },
647→    body: JSON.stringify({
648→      model: config.model,
649→      reasoning: { effort: "low" },
650→      store: true,
651→      ...body,
652→    }),
653→    signal: AbortSignal.timeout(config.timeoutMs),
654→  });
655→
656→  if (!response.ok) {
657→    const errorText = await response.text();
658→    throw new AgentUnavailableError(
659→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
660→    );
661→  }
662→
663→  return (await response.json()) as ResponsesPayload;
664→}
665→
666→// ---------------------------------------------------------------------------
667→// Tool execution with validation
668→// ---------------------------------------------------------------------------
669→
670→function validateEffect(effect: unknown): {
671→  ok: boolean;
672→  data?: Record<string, unknown>;
673→  error?: string;
674→} {
675→  const result = customStyleEffectSchema.safeParse(effect);
676→  if (result.success) {
677→    return { ok: true, data: result.data as Record<string, unknown> };
678→  }
679→
680→  const issues = result.error.issues
681→    .map((i) => `${i.path.join(".")}: ${i.message}`)
682→    .join("; ");
683→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
684→}
685→
686→async function executeToolCall(
687→  call: FunctionCallItem,
688→  callbacks: RunAgentTurnInput["callbacks"],
689→  actions: ActionRecord[],
690→): Promise<string> {
691→  let args: Record<string, unknown>;
692→  try {
693→    args = JSON.parse(call.arguments) as Record<string, unknown>;
694→  } catch {
695→    return JSON.stringify({
696→      ok: false,
697→      error: `Ungültige Tool-Argumente: ${call.arguments}`,
698→    });
699→  }
700→
701→  if (call.name === "create_rule") {
702→    const effectValidation = validateEffect(args.effect);
703→    if (!effectValidation.ok) {
704→      return JSON.stringify({ ok: false, error: effectValidation.error });
705→    }
706→
707→    try {
708→      const { ruleId } = await callbacks.onCreateRule({
709→        selector: args.selector as Record<string, unknown>,
710→        effect: effectValidation.data as Record<string, unknown>,
711→        description: String(args.description ?? ""),
712→      });
713→      actions.push({ type: "created", ruleId });
714→      return JSON.stringify({ ok: true, ruleId });
715→    } catch (error) {
716→      return JSON.stringify({
717→        ok: false,
718→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
719→      });
720→    }
721→  }
722→
723→  if (call.name === "update_rule") {
724→    const effectValidation = validateEffect(args.effect);
725→    if (!effectValidation.ok) {
726→      return JSON.stringify({ ok: false, error: effectValidation.error });
727→    }
728→
729→    const ruleId = String(args.ruleId ?? "");
730→
731→    try {
732→      await callbacks.onUpdateRule({
733→        ruleId,
734→        effect: effectValidation.data as Record<string, unknown>,
735→        description:
736→          typeof args.description === "string" ? args.description : undefined,
737→      });
738→      actions.push({ type: "updated", ruleId });
739→      return JSON.stringify({ ok: true, ruleId });
740→    } catch (error) {
741→      return JSON.stringify({
742→        ok: false,
743→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
744→      });
745→    }
746→  }
747→
748→  if (call.name === "delete_rule") {
749→    const ruleId = String(args.ruleId ?? "");
750→
751→    try {
752→      await callbacks.onDeleteRule(ruleId);
753→      actions.push({ type: "deleted", ruleId });
754→      return JSON.stringify({ ok: true, ruleId });
755→    } catch (error) {
756→      return JSON.stringify({
757→        ok: false,
758→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
759→      });
760→    }
761→  }
762→
763→  return JSON.stringify({
764→    ok: false,
765→    error: `Unbekannter Tool-Call: ${call.name}`,
766→  });
767→}
768→
769→// ---------------------------------------------------------------------------
770→// Main agent turn
771→// ---------------------------------------------------------------------------
772→
773→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
774→  assistantMessage: string;
775→  actions: ActionRecord[];
776→}> {
777→  const config = readAdjustmentAiConfig();
778→
779→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
780→    throw new AgentUnavailableError(
781→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
782→    );
783→  }
784→
785→  const actions: ActionRecord[] = [];
786→  const targetFormat = input.sessionDetail.session.targetFormat;
787→
788→  const inputMessages = buildInputMessages(input);
789→
790→  let payload = await requestOpenAiResponse(
791→    {
792→      input: inputMessages,
793→      tool_choice: "auto",
794→      tools: buildTools(targetFormat),
795→    },
796→    config,
797→  );
798→
799→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
800→    const functionCalls = extractFunctionCalls(payload);
801→    if (functionCalls.length === 0) {
802→      break;
803→    }
804→
805→    if (!payload.id) {
806→      throw new Error(
807→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
808→      );
809→    }
810→
811→    const toolOutputs = [];
812→
813→    for (const call of functionCalls) {
814→      const result = await executeToolCall(call, input.callbacks, actions);
815→      toolOutputs.push({
816→        type: "function_call_output",
817→        call_id: call.callId,
818→        output: result,
819→      });
820→    }
821→
822→    payload = await requestOpenAiResponse(
823→      {
824→        input: toolOutputs,
825→        previous_response_id: payload.id,
826→        tool_choice: "auto",
827→        tools: buildTools(targetFormat),
828→      },
829→      config,
830→    );
831→  }
832→
833→  const rawMessage = extractAssistantMessage(payload);
834→  let assistantMessage: string;
835→
836→  if (rawMessage) {
837→    assistantMessage = rawMessage;
838→  } else if (actions.length > 0) {
839→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
840→  } else {
841→    // The AI returned no text and took no actions — retry once with an
842→    // explicit nudge so the user sees an actual question instead of a
843→    // generic placeholder.
844→    const retryPayload = await requestOpenAiResponse(
845→      {
846→        input: [
847→          ...inputMessages,
848→          {
849→            content: [
850→              {
851→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
852→                type: "input_text",
853→              },
854→            ],
855→            role: "user",
856→          },
857→        ],
858→        tool_choice: "none",
859→        tools: buildTools(targetFormat),
860→      },
861→      config,
862→    );
863→
864→    assistantMessage =
865→      extractAssistantMessage(retryPayload) ||
866→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
867→  }
868→
869→  return { assistantMessage, actions };
870→}
