227→    appendMessage: os.adjustments.appendMessage.handler(async ({ input }) => {
228→      const detail = getAdjustmentSessionDetail(input.sessionId);
229→
230→      if (!detail) {
231→        throw new ORPCError("NOT_FOUND", {
232→          message: "Anpassungssession nicht gefunden.",
233→        });
234→      }
235→
236→      // Phase 1 — Transaction: reopen (if needed) + append user message + reload detail
237→      const latestDetail = withTransaction(() => {
238→        const freshDetail = getAdjustmentSessionDetail(input.sessionId);
239→
240→        if (!freshDetail) {
241→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
242→            message: "Anpassungssession konnte nicht neu geladen werden.",
243→          });
244→        }
245→
246→        if (freshDetail.session.status === "applied") {
247→          reopenAdjustmentSession(input.sessionId);
248→        }
249→
250→        appendAdjustmentMessage(input.sessionId, "user", input.content);
251→
252→        const reloaded = getAdjustmentSessionDetail(input.sessionId);
253→
254→        if (!reloaded) {
255→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
256→            message: "Anpassungssession konnte nicht neu geladen werden.",
257→          });
258→        }
259→
260→        return reloaded;
261→      });
262→
263→      const activeRules = listFormatRules(
264→        detail.session.importId,
265→        detail.session.targetFormat,
266→      ).filter((rule: { status: string }) => rule.status === "active");
267→
268→      // Phase 2 — no wrapper: async AI call
269→      try {
270→        const job = getImportJob(detail.session.importId);
271→        const result = await runAgentTurn({
272→          sessionDetail: latestDetail,
273→          activeRules,
274→          job,
275→          callbacks: {
276→            onCreateRule: async ({ selector, effect, description }) => {
277→              const rule = createFormatRuleDirect({
278→                importId: latestDetail.session.importId,
279→                targetFormat: latestDetail.session.targetFormat,
280→                selector,
281→                effect: {
282→                  type: "custom_style" as const,
283→                  ...effect,
284→                  description,
285→                },
286→                instruction: description,
287→                sourceSessionId: input.sessionId,
288→              });
289→              return { ruleId: rule.id };
290→            },
291→            onUpdateRule: async ({ ruleId, effect, description }) => {
292→              updateFormatRuleEffect(
293→                ruleId,
294→                { type: "custom_style" as const, ...effect, description },
295→                description,
296→              );
297→            },
298→            onDeleteRule: async (ruleId) => {
299→              disableFormatRule(ruleId, latestDetail.session.importId);
300→            },
301→          },
302→        });
303→
304→        // Phase 3 — persist assistant message + events
305→        withTransaction(() => {
306→          appendAdjustmentMessage(
307→            input.sessionId,
308→            "assistant",
309→            result.assistantMessage,
310→          );
311→
312→          for (const action of result.actions) {
313→            recordAdjustmentEvent({
314→              importId: latestDetail.session.importId,
315→              ruleId: action.ruleId,
316→              sessionId: input.sessionId,
317→              targetFormat: latestDetail.session.targetFormat,
318→              type:
319→                action.type === "deleted" ? "rule_disabled" : "rule_applied",
320→            });
321→          }
322→
323→          if (result.actions.length > 0) {
324→            markSessionApplied(input.sessionId);
325→          } else {
326→            recordAdjustmentEvent({
327→              importId: latestDetail.session.importId,
328→              sessionId: input.sessionId,
329→              targetFormat: latestDetail.session.targetFormat,
330→              type: "clarification_requested",
331→            });
332→          }
333→        });
334→      } catch (error) {
335→        if (error instanceof AgentUnavailableError) {
336→          throw new ORPCError("SERVICE_UNAVAILABLE", {
337→            message: error.message,
338→          });
339→        }
340→        if (error instanceof DOMException && error.name === "TimeoutError") {
341→          throw new ORPCError("GATEWAY_TIMEOUT", {
342→            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
343→          });
344→        }
345→        throw new ORPCError("BAD_REQUEST", {
346→          message:
347→            error instanceof Error
348→              ? error.message
349→              : "Die Live-KI-Nachricht konnte nicht verarbeitet werden.",
350→        });
351→      }
352→
353→      const nextDetail = getAdjustmentSessionDetail(input.sessionId);
354→
355→      if (!nextDetail) {
356→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
357→          message: "Anpassungssession konnte nicht neu geladen werden.",
358→        });
359→      }
360→
361→      return nextDetail;
362→    }),
