 60→function getBodyInputRecord(body: Record<string, unknown>, index: number) {
 61→  const { input } = body;
 62→
 63→  if (!Array.isArray(input)) {
 64→    return null;
 65→  }
 66→
 67→  const entry = input[index];
 68→
 69→  if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
 70→    return null;
 71→  }
 72→
 73→  return entry as Record<string, unknown>;
 74→}
 75→
 76→function getBodyInputText(body: Record<string, unknown>, index: number) {
 77→  const entry = getBodyInputRecord(body, index);
 78→  const content = entry?.content;
 79→
 80→  if (!Array.isArray(content)) {
 81→    return "";
 82→  }
 83→
 84→  const firstContentPart = content[0];
 85→
 86→  if (
 87→    !firstContentPart ||
 88→    typeof firstContentPart !== "object" ||
 89→    Array.isArray(firstContentPart)
 90→  ) {
 91→    return "";
 92→  }
 93→
 94→  return typeof firstContentPart.text === "string" ? firstContentPart.text : "";
 95→}
 96→
 97→function getBodyInputOutput(body: Record<string, unknown>, index: number) {
 98→  const entry = getBodyInputRecord(body, index);
 99→
100→  return typeof entry?.output === "string" ? entry.output : "";
101→}
