225→function appendTail(tail: string[], chunk: string) {
226→  for (const line of chunk.split(/\r?\n/)) {
227→    if (!line.trim()) {
228→      continue;
229→    }
230→
231→    tail.push(line);
232→
233→    if (tail.length > 40) {
234→      tail.shift();
235→    }
236→  }
237→}
