260→  child.stdout.setEncoding("utf8");
261→  child.stderr.setEncoding("utf8");
262→  child.stdout.on("data", (chunk: string) => {
263→    appendTail(managedChild.tail, chunk);
264→  });
265→  child.stderr.on("data", (chunk: string) => {
266→    appendTail(managedChild.tail, chunk);
267→  });
268→
269→  return managedChild;
270→}
