272→function readRequestBody(request: http.IncomingMessage) {
273→  return new Promise<string>((resolve, reject) => {
274→    const chunks: Buffer[] = [];
275→
276→    request.on("data", (chunk) => {
277→      chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(String(chunk)));
278→    });
279→    request.once("end", () => resolve(Buffer.concat(chunks).toString("utf8")));
280→    request.once("error", reject);
281→  });
282→}
