441→async function startMockOpenAiServer(): Promise<ManagedMockServer> {
442→  const server = http.createServer(async (request, response) => {
443→    if (request.method !== "POST" || request.url !== "/v1/responses") {
444→      response.writeHead(404).end("not found");
445→      return;
446→    }
447→
448→    const rawBody = await readRequestBody(request);
449→    const body = JSON.parse(rawBody) as Record<string, unknown>;
450→    const isPreviewCompilation = Boolean(
451→      (body.text as Record<string, unknown> | undefined)?.format,
452→    );
453→    const isFollowUp = typeof body.previous_response_id === "string";
454→    const payload = isPreviewCompilation
455→      ? {
456→          output_text: JSON.stringify(buildMockPreviewResponse(body)),
457→        }
458→      : isFollowUp
459→        ? buildMockFollowUpResponse(body)
460→        : buildMockChatResponse(body);
461→
462→    response.writeHead(200, {
463→      "Content-Type": "application/json",
464→    });
465→    response.end(JSON.stringify(payload));
466→  });
467→
468→  await new Promise<void>((resolve, reject) => {
469→    server.listen(mockOpenAiPort, "127.0.0.1", () => resolve());
470→    server.once("error", reject);
471→  });
472→
473→  return {
474→    close: async () => {
475→      await new Promise<void>((resolve, reject) => {
476→        server.close((error) => {
477→          if (error) {
478→            reject(error);
479→            return;
480→          }
481→
482→          resolve();
483→        });
484→      });
485→    },
486→    url: `http://127.0.0.1:${mockOpenAiPort}/v1`,
487→  };
488→}
