490→async function waitForPort(port: number, label: string) {
491→  const startedAt = Date.now();
492→
493→  while (Date.now() - startedAt < 45_000) {
494→    try {
495→      await new Promise<void>((resolve, reject) => {
496→        const socket = net.createConnection(
497→          {
498→            host: "127.0.0.1",
499→            port,
500→          },
501→          () => {
502→            socket.end();
503→            resolve();
504→          },
505→        );
506→
507→        socket.setTimeout(1_000);
508→        socket.once("timeout", () => {
509→          socket.destroy();
510→          reject(new Error("timeout"));
511→        });
512→        socket.once("error", reject);
513→      });
514→      return;
515→    } catch {
516→      // Retry until timeout.
517→    }
518→
519→    await delay(500);
520→  }
521→
522→  throw new Error(`Timed out while waiting for ${label} on port ${port}.`);
523→}
