535→async function stopManagedProcess(child: ManagedChild) {
536→  if (child.process.exitCode !== null || child.process.killed) {
537→    return;
538→  }
539→
540→  child.process.kill("SIGTERM");
541→  await Promise.race([
542→    new Promise<void>((resolve) => {
543→      child.process.once("exit", () => resolve());
544→    }),
545→    delay(5_000),
546→  ]);
547→
548→  if (child.process.exitCode === null && !child.process.killed) {
549→    child.process.kill("SIGKILL");
550→  }
551→}
