 26→/**
 27→ * Read the DOM content of the editable element and construct a new Block
 28→ * that matches the original block's type, preserving type-specific fields
 29→ * (e.g. heading level, code language, list ordered flag).
 30→ */
 31→function readBlockFromDom(element: HTMLElement, original: Block): Block {
 32→  switch (original.type) {
 33→    case "paragraph":
 34→      return {
 35→        id: original.id,
 36→        type: "paragraph",
 37→        text: element.textContent ?? "",
 38→      };
 39→
 40→    case "heading":
 41→      return {
 42→        id: original.id,
 43→        type: "heading",
 44→        level: original.level,
 45→        text: element.textContent ?? "",
 46→      };
 47→
 48→    case "quote":
 49→      return {
 50→        id: original.id,
 51→        type: "quote",
 52→        text: element.textContent ?? "",
 53→      };
 54→
 55→    case "code": {
 56→      const codeEl = element.querySelector("pre code");
 57→      return {
 58→        id: original.id,
 59→        type: "code",
 60→        language: original.language,
 61→        text: codeEl ? (codeEl.textContent ?? "") : (element.textContent ?? ""),
 62→      };
 63→    }
 64→
 65→    case "list": {
 66→      const listItems = element.querySelectorAll("li");
 67→      const items = Array.from(listItems).map((li) => li.textContent ?? "");
 68→      return {
 69→        id: original.id,
 70→        type: "list",
 71→        ordered: original.ordered,
 72→        items: items.length > 0 ? items : [element.textContent ?? ""],
 73→      };
 74→    }
 75→
 76→    case "table": {
 77→      const thElements = element.querySelectorAll("th");
 78→      const headers = Array.from(thElements).map((th) => th.textContent ?? "");
 79→
 80→      const bodyRows = element.querySelectorAll("tbody tr");
 81→      const rows = Array.from(bodyRows).map((tr) => {
 82→        const cells = tr.querySelectorAll("td");
 83→        return Array.from(cells).map((td) => td.textContent ?? "");
 84→      });
 85→
 86→      return { id: original.id, type: "table", headers, rows };
 87→    }
 88→
 89→    default:
 90→      return original;
 91→  }
 92→}
 93→
 94→export function EditableBlock({
 95→  block,
 96→  blockIndex,
 97→  messageId,
 98→  onBlockChange,
 99→  children,
100→}: EditableBlockProps) {
101→  const ref = useRef<HTMLDivElement>(null);
102→
103→  const handleBlur = useCallback(() => {
104→    const element = ref.current;
105→    if (!element) return;
106→
107→    const newBlock = readBlockFromDom(element, block);
108→    onBlockChange(messageId, blockIndex, newBlock);
109→  }, [block, blockIndex, messageId, onBlockChange]);
110→
111→  const handleKeyDown = useCallback(
112→    (event: React.KeyboardEvent<HTMLDivElement>) => {
113→      if (event.key === "Escape") {
114→        event.currentTarget.blur();
115→      }
116→    },
117→    [],
118→  );
119→
120→  const handlePaste = useCallback(
121→    (event: React.ClipboardEvent<HTMLDivElement>) => {
122→      event.preventDefault();
123→      const plainText = event.clipboardData.getData("text/plain");
124→      const selection = window.getSelection();
125→      if (selection && selection.rangeCount > 0) {
126→        const range = selection.getRangeAt(0);
127→        range.deleteContents();
128→        range.insertNode(document.createTextNode(plainText));
129→        range.collapse(false);
130→      }
131→    },
132→    [],
133→  );
134→
135→  const isCodeBlock = block.type === "code";
136→
137→  return (
138→    /* biome-ignore lint/a11y/useSemanticElements: contentEditable div wraps arbitrary block content, not a simple text input */
139→    <div
140→      ref={ref}
141→      role="textbox"
142→      tabIndex={0}
143→      data-testid="editable-block"
144→      contentEditable
145→      suppressContentEditableWarning
146→      onBlur={handleBlur}
147→      onKeyDown={handleKeyDown}
148→      onPaste={handlePaste}
149→      className={cn(
150→        "outline-none rounded-md ring-0 focus:ring-1 focus:ring-blue-300 transition-shadow",
151→        isCodeBlock && "whitespace-pre-wrap",
152→      )}
153→    >
154→      <FrozenChildren>{children}</FrozenChildren>
155→    </div>
156→  );
157→}
