169→      updatedBlocks.splice(blockIndex, 1);
170→      onBlocksChange(message.id, updatedBlocks);
171→    },
172→    [message.id, onBlocksChange],
173→  );
174→
175→  const handleDuplicateBlock = useCallback(
176→    (blockIndex: number) => {
177→      if (!onBlocksChange) return;
178→      const updatedBlocks = [...blocksRef.current];
179→      const original = updatedBlocks[blockIndex];
180→      if (!original) return;
181→      const copy = { ...original, id: generateBlockId() } as Block;
182→      updatedBlocks.splice(blockIndex + 1, 0, copy);
183→      onBlocksChange(message.id, updatedBlocks);
184→    },
185→    [message.id, onBlocksChange],
186→  );
187→
188→  const handleMoveUp = useCallback(
189→    (blockIndex: number) => {
190→      if (!onBlocksChange || blockIndex === 0) return;
191→      const updatedBlocks = [...blocksRef.current];
192→      const current = updatedBlocks[blockIndex];
193→      const above = updatedBlocks[blockIndex - 1];
194→      if (!current || !above) return;
195→      updatedBlocks[blockIndex - 1] = current;
196→      updatedBlocks[blockIndex] = above;
197→      onBlocksChange(message.id, updatedBlocks);
198→    },
199→    [message.id, onBlocksChange],
200→  );
201→
202→  const handleMoveDown = useCallback(
203→    (blockIndex: number) => {
204→      if (!onBlocksChange || blockIndex >= blocksRef.current.length - 1) return;
205→      const updatedBlocks = [...blocksRef.current];
206→      const current = updatedBlocks[blockIndex];
207→      const below = updatedBlocks[blockIndex + 1];
208→      if (!current || !below) return;
209→      updatedBlocks[blockIndex] = below;
210→      updatedBlocks[blockIndex + 1] = current;
211→      onBlocksChange(message.id, updatedBlocks);
212→    },
213→    [message.id, onBlocksChange],
214→  );
215→
216→  const handleInsertBlock = useCallback(
217→    (blockIndex: number, block: Block) => {
218→      if (!onBlocksChange) return;
219→      const updatedBlocks = [...blocksRef.current];
220→      updatedBlocks.splice(blockIndex, 0, block);
221→      onBlocksChange(message.id, updatedBlocks);
222→    },
223→    [message.id, onBlocksChange],
224→  );
225→
226→  return (
227→    <article
228→      className={cn(
229→        "rounded-[1.55rem] border border-border/80 px-4 py-5 sm:px-5",
230→        message.role === "assistant" ? "bg-card/92" : "bg-secondary/30",
231→        isDeleted && "opacity-50",
232→      )}
233→    >
234→      {isDeleted && (
235→        <div className="mb-3 flex items-center justify-between rounded-xl bg-red-50 border border-red-200/60 px-3 py-2 text-xs text-red-700">
236→          <span>Gelöscht</span>
237→          {onRestore && (
238→            <button
239→              type="button"
240→              className="text-red-600 hover:text-red-800 underline"
241→              onClick={(e) => {
242→                e.stopPropagation();
243→                onRestore();
244→              }}
245→            >
246→              Wiederherstellen
247→            </button>
248→          )}
249→        </div>
250→      )}
251→      <div className="mb-4 flex items-center gap-3 text-xs uppercase tracking-[0.18em] text-muted-foreground">
252→        <span>{getRoleLabel(message.role)}</span>
253→        <span>{messageIndex + 1}</span>
254→        {!isDeleted && (onDeleteMessage || onCopyMessage) && (
255→          <span className="ml-auto flex items-center gap-1">
256→            {onCopyMessage && (
257→              <button
258→                type="button"
259→                className="rounded-lg p-1.5 text-muted-foreground hover:bg-secondary/50 hover:text-foreground transition-colors"
260→                onClick={(e) => {
261→                  e.stopPropagation();
262→                  onCopyMessage();
263→                }}
264→                aria-label="Nachricht kopieren"
265→                data-testid={`copy-message-${message.id}`}
266→              >
267→                <ClipboardCopy className="h-4 w-4" />
268→              </button>
269→            )}
270→            {onDeleteMessage && onDeleteRound && (
271→              <MessageDeleteMenu
272→                onDeleteMessage={onDeleteMessage}
273→                onDeleteRound={onDeleteRound}
274→              />
275→            )}
276→          </span>
277→        )}
278→      </div>
279→      <div className="space-y-4">
280→        {message.blocks.map((block, blockIndex) => {
281→          const blockText = blockToPlainText(block);
282→          const blockEffects =
283→            effectsMap.get(`${message.id}:${block.id}`) ?? [];
284→          const isSelected =
285→            selectedBlock?.messageId === message.id &&
286→            selectedBlock.blockIndex === blockIndex;
287→          const isHighlighted = highlightedBlocks.has(
288→            `${message.id}:${block.id}`,
289→          );
290→          const emitSelection = (
291→            anchor: ViewportAnchor,
292→            selectedText: string,
293→          ) => {
294→            lastSelectionInteractionAt.current = Date.now();
295→
296→            onSelectBlock(
297→              {
298→                blockId: block.id,
299→                blockIndex,
300→                blockType: block.type,
301→                messageId: message.id,
302→                messageIndex,
303→                messageRole: message.role,
304→                selectedText,
305→                textQuote: truncateSelectionText(selectedText),
306→              },
307→              anchor,
308→            );
309→          };
310→
311→          const inserts = collectInserts(blockEffects);
312→
313→          return (
314→            <React.Fragment key={block.id}>
315→              {inserts.insertBefore === "hr" && (
316→                <hr className="border-border/40" />
317→              )}
318→              {inserts.insertBefore === "spacer" && <div className="h-6" />}
319→              {/* biome-ignore lint/a11y/noStaticElementInteractions: hover tracking for block toolbar */}
320→              <div
321→                className="relative"
322→                onMouseEnter={() => handleBlockMouseEnter(blockIndex)}
323→                onMouseLeave={handleBlockMouseLeave}
324→              >
325→                {editMode &&
326→                  onBlocksChange &&
327→                  hoveredBlockIndex === blockIndex && (
328→                    <BlockToolbar
329→                      block={block}
330→                      blockIndex={blockIndex}
331→                      totalBlocks={message.blocks.length}
332→                      onDelete={handleDeleteBlock}
333→                      onDuplicate={handleDuplicateBlock}
334→                      onInsertBlock={handleInsertBlock}
335→                      onMenuOpenChange={handleToolbarMenuOpenChange}
336→                      onMoveUp={handleMoveUp}
337→                      onMoveDown={handleMoveDown}
338→                    />
339→                  )}
340→                {/* biome-ignore lint/a11y/useKeyWithClickEvents: block selection is pointer-only by design */}
341→                {/* biome-ignore lint/a11y/noStaticElementInteractions: block selection uses onPointerUp + onClick */}
342→                <div
343→                  data-testid={`reader-block-${message.id}-${blockIndex}`}
344→                  className={getReaderBlockClassName({
345→                    adjustModeEnabled,
346→                    effects: blockEffects,
347→                    isHighlighted,
348→                    isSelected,
349→                  })}
350→                  style={getReaderBlockStyle(blockEffects)}
351→                  data-selected={isSelected ? "true" : "false"}
352→                  onPointerUp={(event) => {
353→                    if (!adjustModeEnabled) {
354→                      return;
355→                    }
356→
357→                    const selection = window.getSelection();
358→                    const range =
359→                      selection && selection.rangeCount > 0
360→                        ? selection.getRangeAt(0)
361→                        : null;
362→                    const selectedText = selection?.toString().trim() ?? "";
363→                    const container = event.currentTarget;
364→                    const rangeStartContainer = range?.startContainer ?? null;
365→                    const rangeEndContainer = range?.endContainer ?? null;
366→                    const hasLocalTextSelection =
367→                      Boolean(selectedText) &&
368→                      Boolean(rangeStartContainer) &&
369→                      Boolean(rangeEndContainer) &&
370→                      container.contains(rangeStartContainer) &&
371→                      container.contains(rangeEndContainer);
372→                    const anchorRect =
373→                      hasLocalTextSelection && range
374→                        ? range.getBoundingClientRect()
375→                        : container.getBoundingClientRect();
376→
377→                    emitSelection(
378→                      toViewportAnchor(anchorRect),
379→                      hasLocalTextSelection ? selectedText : blockText,
380→                    );
381→
382→                    if (selection && hasLocalTextSelection) {
383→                      selection.removeAllRanges();
384→                    }
385→                  }}
386→                  onClick={(event) => {
387→                    if (!adjustModeEnabled) {
388→                      return;
389→                    }
390→
391→                    if (
392→                      Date.now() - lastSelectionInteractionAt.current <
393→                      SELECTION_DEBOUNCE_MS
394→                    ) {
395→                      return;
396→                    }
397→
398→                    emitSelection(
399→                      toViewportAnchor(
400→                        event.currentTarget.getBoundingClientRect(),
401→                      ),
402→                      blockText,
403→                    );
404→                  }}
405→                >
406→                  <ErrorBoundary
407→                    fallback={<BlockErrorFallback blockType={block.type} />}
408→                  >
409→                    {editMode && onBlockChange && block.type === "table" ? (
410→                      <TableEditor
411→                        block={block}
412→                        messageId={message.id}
413→                        blockIndex={blockIndex}
414→                        effects={blockEffects}
415→                        onBlockChange={onBlockChange}
416→                      />
417→                    ) : editMode && onBlockChange ? (
418→                      <EditableBlock
419→                        block={block}
420→                        blockIndex={blockIndex}
421→                        messageId={message.id}
422→                        onBlockChange={onBlockChange}
423→                      >
424→                        <BlockRenderer block={block} effects={blockEffects} />
425→                      </EditableBlock>
426→                    ) : (
427→                      <BlockRenderer block={block} effects={blockEffects} />
428→                    )}
429→                  </ErrorBoundary>
430→                </div>
431→                {/* BlockInserter removed — insert is now in BlockToolbar */}
432→              </div>
433→              {inserts.insertAfter === "hr" && (
434→                <hr className="border-border/40" />
435→              )}
436→              {inserts.insertAfter === "spacer" && <div className="h-6" />}
437→            </React.Fragment>
438→          );
439→        })}
440→      </div>
441→    </article>
442→  );
443→});
