445→export function ReaderView({
446→  activeRules,
447→  adjustModeEnabled,
448→  conversation,
449→  deletedMessageIds,
450→  editMode,
451→  effectsMap,
452→  highlightedRuleId,
453→  onBlocksChange,
454→  onCopyMessage,
455→  onDeleteMessage,
456→  onDeleteRound,
457→  onRestoreMessage,
458→  onSelectBlock,
459→  selectedBlock,
460→  showDeleted,
461→}: ReaderViewProps) {
462→  const visibleMessages = useMemo(() => {
463→    if (!conversation?.messages) return [];
464→    if (!deletedMessageIds?.size) return conversation.messages;
465→    if (showDeleted) return conversation.messages;
466→    return conversation.messages.filter((m) => !deletedMessageIds.has(m.id));
467→  }, [conversation?.messages, deletedMessageIds, showDeleted]);
468→
469→  // Tracks the latest in-progress blocks per message so that consecutive edits
470→  // within the same debounce window build on top of each other rather than on
471→  // stale props (which would cause earlier edits to be overwritten).
472→  const pendingBlocksRef = useRef<Map<string, Block[]>>(new Map());
473→
474→  // When the conversation prop updates (i.e. the parent has persisted the edit
475→  // and passed the new data back down), clear any pending entries whose blocks
476→  // now match the incoming props — they are no longer "in-flight".
477→  useEffect(() => {
478→    if (!conversation) return;
479→    const pending = pendingBlocksRef.current;
480→    for (const [messageId] of pending) {
481→      const message = conversation.messages.find((m) => m.id === messageId);
482→      if (!message) {
483→        pending.delete(messageId);
484→        continue;
485→      }
486→      // If the prop blocks now reflect our last pending write, the save has
487→      // been acknowledged — remove the entry so the next edit starts fresh.
488→      const pendingBlocks = pending.get(messageId);
489→      if (
490→        pendingBlocks &&
491→        pendingBlocks.length === message.blocks.length &&
492→        pendingBlocks.every((b, i) => b === message.blocks[i])
493→      ) {
494→        pending.delete(messageId);
495→      }
496→    }
497→  }, [conversation]);
498→
499→  const highlightedBlocks = useMemo(() => {
500→    if (!highlightedRuleId || !conversation) {
501→      return new Set<string>();
502→    }
503→
504→    const rule = activeRules.find(
505→      (r) => r.id === highlightedRuleId && r.status === "active",
506→    );
507→
508→    if (!rule) {
509→      return new Set<string>();
510→    }
511→
512→    const matches = getBlocksMatchingRule(rule, conversation);
513→    return new Set(matches.map((m) => `${m.messageId}:${m.blockId}`));
514→  }, [highlightedRuleId, activeRules, conversation]);
515→
516→  const handleBlockChange = useCallback(
517→    (messageId: string, blockIndex: number, newBlock: Block) => {
518→      if (!onBlocksChange || !conversation) return;
519→      const message = conversation.messages.find((m) => m.id === messageId);
520→      if (!message) return;
521→
522→      // Use pending blocks as the base if present (prevents stale-closure
523→      // overwrites when the user edits multiple blocks before the debounced
524→      // save propagates updated props back down).
525→      const baseBlocks =
526→        pendingBlocksRef.current.get(messageId) ?? message.blocks;
527→
528→      const updatedBlocks = baseBlocks.map((b, i) =>
529→        i === blockIndex ? newBlock : b,
530→      );
531→
532→      pendingBlocksRef.current.set(messageId, updatedBlocks);
533→      onBlocksChange(messageId, updatedBlocks);
534→    },
535→    [onBlocksChange, conversation],
536→  );
537→
538→  if (!conversation?.messages.length) {
539→    return (
540→      <div className="rounded-2xl border border-border/80 bg-card/75 px-4 py-5 text-sm text-muted-foreground">
541→        Für diesen Import ist noch kein Transkriptinhalt verfügbar.
542→      </div>
543→    );
544→  }
545→
546→  return (
547→    <div className="space-y-3">
548→      {visibleMessages.map((message, index) => (
549→        <ReaderMessage
550→          key={message.id}
551→          adjustModeEnabled={adjustModeEnabled}
552→          editMode={editMode}
553→          effectsMap={effectsMap}
554→          highlightedBlocks={highlightedBlocks}
555→          message={message}
556→          messageIndex={index}
557→          onBlockChange={editMode ? handleBlockChange : undefined}
558→          onBlocksChange={editMode ? onBlocksChange : undefined}
559→          onCopyMessage={
560→            onCopyMessage ? () => onCopyMessage(message.id) : undefined
561→          }
562→          onSelectBlock={onSelectBlock}
563→          selectedBlock={selectedBlock}
564→          isDeleted={deletedMessageIds?.has(message.id)}
565→          onDeleteMessage={
566→            onDeleteMessage ? () => onDeleteMessage(message.id) : undefined
567→          }
568→          onDeleteRound={
569→            onDeleteRound ? () => onDeleteRound(message.id) : undefined
570→          }
571→          onRestore={
572→            onRestoreMessage
573→              ? () => {
574→                  void onRestoreMessage(message.id);
575→                }
576→              : undefined
577→          }
578→        />
579→      ))}
580→    </div>
581→  );
582→}
