 26→// ---------------------------------------------------------------------------
 27→// EditableCell — uncontrolled contentEditable div
 28→// ---------------------------------------------------------------------------
 29→
 30→function EditableCell({
 31→  value,
 32→  onCommit,
 33→}: {
 34→  value: string;
 35→  onCommit: (v: string) => void;
 36→}) {
 37→  const ref = useRef<HTMLDivElement>(null);
 38→
 39→  useEffect(() => {
 40→    if (ref.current && ref.current.textContent !== value) {
 41→      ref.current.textContent = value;
 42→    }
 43→  }, [value]);
 44→
 45→  return (
 46→    /* biome-ignore lint/a11y/useSemanticElements: contentEditable div wraps arbitrary block content, not a simple text input */
 47→    <div
 48→      ref={ref}
 49→      role="textbox"
 50→      tabIndex={0}
 51→      contentEditable
 52→      suppressContentEditableWarning
 53→      onBlur={() => {
 54→        const text = ref.current?.textContent ?? "";
 55→        if (text !== value) onCommit(text);
 56→      }}
 57→      onKeyDown={(e) => {
 58→        if (e.key === "Enter") {
 59→          e.preventDefault();
 60→          ref.current?.blur();
 61→        }
 62→      }}
 63→      className="min-w-[2rem] px-1 outline-none"
 64→    />
 65→  );
 66→}
