 71→
 72→export function TableEditor({
 73→  block,
 74→  messageId,
 75→  blockIndex,
 76→  effects,
 77→  onBlockChange,
 78→}: TableEditorProps) {
 79→  const tableRef = useRef<HTMLDivElement>(null);
 80→
 81→  const handleHeaderChange = useCallback(
 82→    (colIndex: number, value: string) => {
 83→      const newHeaders = [...block.headers];
 84→      newHeaders[colIndex] = value;
 85→      onBlockChange(messageId, blockIndex, { ...block, headers: newHeaders });
 86→    },
 87→    [block, messageId, blockIndex, onBlockChange],
 88→  );
 89→
 90→  const handleCellChange = useCallback(
 91→    (rowIndex: number, colIndex: number, value: string) => {
 92→      const newRows = block.rows.map((row, ri) =>
 93→        ri === rowIndex
 94→          ? row.map((cell, ci) => (ci === colIndex ? value : cell))
 95→          : row,
 96→      );
 97→      onBlockChange(messageId, blockIndex, { ...block, rows: newRows });
 98→    },
 99→    [block, messageId, blockIndex, onBlockChange],
100→  );
101→
102→  const handleAddRow = useCallback(
103→    () => onBlockChange(messageId, blockIndex, addRow(block)),
104→    [block, messageId, blockIndex, onBlockChange],
105→  );
106→
107→  const handleAddColumn = useCallback(
108→    () => onBlockChange(messageId, blockIndex, addColumn(block)),
109→    [block, messageId, blockIndex, onBlockChange],
110→  );
111→
112→  const handleRemoveRow = useCallback(
113→    (rowIndex: number) =>
114→      onBlockChange(messageId, blockIndex, removeRow(block, rowIndex)),
115→    [block, messageId, blockIndex, onBlockChange],
116→  );
117→
118→  const handleRemoveColumn = useCallback(
119→    (colIndex: number) =>
120→      onBlockChange(messageId, blockIndex, removeColumn(block, colIndex)),
121→    [block, messageId, blockIndex, onBlockChange],
122→  );
123→
124→  // Tab navigation across all editable cells in the table
125→  const handleTableKeyDown = useCallback(
126→    (e: React.KeyboardEvent<HTMLDivElement>) => {
127→      if (e.key !== "Tab") return;
128→      if (!tableRef.current) return;
129→
130→      const cells = tableRef.current.querySelectorAll("[contenteditable]");
131→      if (cells.length === 0) return;
132→
133→      const currentIndex = Array.from(cells).indexOf(
134→        document.activeElement as Element,
135→      );
136→      if (currentIndex === -1) return;
137→
138→      e.preventDefault();
139→
140→      const nextIndex = e.shiftKey ? currentIndex - 1 : currentIndex + 1;
141→      if (nextIndex >= 0 && nextIndex < cells.length) {
142→        (cells[nextIndex] as HTMLElement).focus();
143→      }
144→    },
145→    [],
146→  );
147→
148→  const containerStyle = getReaderBlockStyle(effects);
149→  const showRemoveCol = canRemoveColumn(block);
150→  const showRemoveRow = canRemoveRow(block);
151→  const showAddCol = canAddColumn(block);
152→  const showAddRow = canAddRow(block);
153→
154→  return (
155→    /* biome-ignore lint/a11y/useSemanticElements: div container for table with keyboard navigation */
156→    <div
157→      ref={tableRef}
158→      role="group"
159→      style={containerStyle}
160→      className="overflow-x-auto rounded-2xl border border-border/80"
161→      onKeyDown={handleTableKeyDown}
162→    >
163→      <table className="min-w-full table-fixed text-left text-sm">
164→        <thead className="bg-secondary/70 text-secondary-foreground">
165→          <tr>
166→            {block.headers.map((header, colIndex) => (
167→              <th
168→                key={`h-${colIndex}`}
169→                className="group relative px-4 py-3 font-medium"
170→              >
171→                <EditableCell
172→                  value={header}
173→                  onCommit={(v) => handleHeaderChange(colIndex, v)}
174→                />
175→                {showRemoveCol && (
176→                  <button
177→                    type="button"
178→                    className="absolute -top-2 right-1 hidden rounded-full bg-destructive/80 px-1.5 text-xs text-destructive-foreground group-hover:block"
179→                    onClick={() => handleRemoveColumn(colIndex)}
180→                    aria-label="Spalte entfernen"
181→                  >
182→                    &times;
183→                  </button>
184→                )}
185→              </th>
186→            ))}
187→            {showAddCol && (
188→              <th className="w-8">
189→                <button
190→                  type="button"
191→                  className="flex h-full w-full items-center justify-center text-muted-foreground hover:text-foreground"
192→                  onClick={handleAddColumn}
193→                  aria-label="Spalte hinzufügen"
194→                >
195→                  +
196→                </button>
197→              </th>
198→            )}
199→          </tr>
200→        </thead>
201→        <tbody>
202→          {block.rows.map((row, rowIndex) => (
203→            <tr
204→              key={`r-${rowIndex}`}
205→              className="group border-t border-border/80"
206→            >
207→              {row.map((cell, colIndex) => (
208→                <td
209→                  key={`c-${rowIndex}-${colIndex}`}
210→                  className="px-4 py-3 align-top text-muted-foreground"
211→                >
212→                  <EditableCell
213→                    value={cell}
214→                    onCommit={(v) => handleCellChange(rowIndex, colIndex, v)}
215→                  />
216→                </td>
217→              ))}
218→              {showRemoveRow && (
219→                <td className="px-1 py-3">
220→                  <button
221→                    type="button"
222→                    className="hidden rounded-full bg-destructive/80 px-1.5 text-xs text-destructive-foreground group-hover:block"
223→                    onClick={() => handleRemoveRow(rowIndex)}
224→                    aria-label="Zeile entfernen"
225→                  >
226→                    &times;
227→                  </button>
228→                </td>
229→              )}
230→            </tr>
231→          ))}
232→        </tbody>
233→      </table>
234→      {showAddRow && (
235→        <button
236→          type="button"
237→          className="w-full border-t border-dashed border-border/80 py-2 text-center text-sm text-muted-foreground hover:bg-secondary/30 hover:text-foreground"
238→          onClick={handleAddRow}
239→          aria-label="Zeile hinzufügen"
240→        >
241→          + Zeile
242→        </button>
243→      )}
244→    </div>
245→  );
246→}
