140→
141→  // Track how many dropdowns are open so the parent can prevent unmounting
142→  const [, setOpenCount] = useState(0);
143→  const handleDropdownOpenChange = useCallback(
144→    (open: boolean) => {
145→      setOpenCount((c) => {
146→        const next = c + (open ? 1 : -1);
147→        onMenuOpenChange?.(next > 0);
148→        return next;
149→      });
150→    },
151→    [onMenuOpenChange],
152→  );
153→
154→  const handleInsertSelect = useCallback(
155→    (key: string) => {
156→      const template = BLOCK_DEFAULTS[key];
157→      if (template) {
158→        onInsertBlock(blockIndex + 1, {
159→          ...template,
160→          id: generateBlockId(),
161→        } as Block);
162→      }
163→    },
164→    [blockIndex, onInsertBlock],
165→  );
166→
167→  return (
168→    <div className="absolute -top-8 left-0 z-10 flex items-center gap-0.5 rounded-lg border border-border/60 bg-background px-1 py-0.5 shadow-sm">
