171→        <DropdownMenuTrigger asChild>
172→          <button
173→            type="button"
174→            className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-secondary hover:text-foreground transition-colors"
175→            aria-label="Block einfügen"
176→          >
177→            <Plus className="h-3.5 w-3.5" />
178→          </button>
179→        </DropdownMenuTrigger>
180→        <DropdownMenuContent align="start" className="w-44">
181→          <DropdownMenuLabel className="text-xs">
182→            Einfügen nach
183→          </DropdownMenuLabel>
184→          <DropdownMenuSeparator />
185→          {INSERT_BLOCK_ITEMS.map(({ key, label, icon: Icon }) =>
186→            key === "table" ? (
187→              <DropdownMenuSub key={key}>
188→                <DropdownMenuSubTrigger>
189→                  <Icon className="h-4 w-4" />
190→                  <span>{label}</span>
191→                </DropdownMenuSubTrigger>
192→                <DropdownMenuSubContent>
193→                  <TableGridPicker
