199→                    }}
200→                  />
201→                </DropdownMenuSubContent>
202→              </DropdownMenuSub>
203→            ) : (
204→              <DropdownMenuItem
205→                key={key}
206→                onSelect={() => handleInsertSelect(key)}
207→              >
208→                <Icon className="h-4 w-4" />
209→                <span>{label}</span>
210→              </DropdownMenuItem>
211→            ),
212→          )}
213→        </DropdownMenuContent>
214→      </DropdownMenu>
215→
216→      {/* Move up */}
217→      <button
218→        type="button"
219→        className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-secondary hover:text-foreground transition-colors disabled:opacity-30 disabled:pointer-events-none"
220→        aria-label="Block nach oben"
221→        disabled={isFirst}
222→        onClick={() => onMoveUp(blockIndex)}
223→      >
224→        <ArrowUp className="h-3.5 w-3.5" />
225→      </button>
226→
227→      {/* Move down */}
228→      <button
229→        type="button"
230→        className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-secondary hover:text-foreground transition-colors disabled:opacity-30 disabled:pointer-events-none"
231→        aria-label="Block nach unten"
232→        disabled={isLast}
233→        onClick={() => onMoveDown(blockIndex)}
234→      >
235→        <ArrowDown className="h-3.5 w-3.5" />
236→      </button>
237→
238→      {/* Duplicate */}
239→      <button
240→        type="button"
241→        className="flex h-6 w-6 items-center justify-center rounded text-muted-foreground hover:bg-secondary hover:text-foreground transition-colors"
242→        aria-label="Block duplizieren"
