  13→const DEFAULT_CEREBRAS_API_BASE_URL = "https://api.cerebras.ai/v1";
  14→const DEFAULT_MAX_MESSAGES = 24;
  15→const DEFAULT_MAX_MESSAGE_CHARS = 18_000;
  16→const DEFAULT_CONCURRENCY = 2;
  17→const DEFAULT_TIMEOUT_MS = 60_000;
  18→const DEFAULT_CEREBRAS_MAX_COMPLETION_TOKENS = 4096;
  19→const DEFAULT_CEREBRAS_REASONING_EFFORT = "low";
  20→const MIN_REPAIR_SCORE = 4;
  21→const STRUCTURE_HINT_PATTERN =
  22→  /(^|\n)([-*]\s+\S+|\d+\.\s+\S+|#{1,6}\s+\S+|>\s+\S+|```|`[^`]+`|\|.+\|)/m;
  23→const PARAGRAPH_BLOCK_SYNTAX_PATTERN =
  24→  /(^|\n)(#{1,6}\s+\S+|[-*]\s+\S+|\d+\.\s+\S+|>\s+\S+|```|\|.+\|)/gm;
  25→const EMPHASIZED_STEP_PATTERN = /(?:^|\n\n)\*\*\d+\.\s+.+?\*\*(?=\n\n|$)/gm;
  26→
  27→type StructuringMetadata = NonNullable<
  28→  NormalizedSnapshotPayload["structuring"]
  29→>;
  30→type StructuredSnapshotMessage = NormalizedSnapshotMessage & {
  31→  parser: NonNullable<NormalizedSnapshotMessage["parser"]>;
  32→};
  33→
  34→type CandidateMessage = {
  35→  kind: "message" | "block";
  36→  index: number;
  37→  message: StructuredSnapshotMessage;
  38→  reasons: string[];
  39→  score: number;
  40→  blockIndex?: number;
  41→};
  42→
  43→type StructuringConfig = {
  44→  concurrency: number;
  45→  maxMessages: number;
  46→  maxMessageChars: number;
  47→  timeoutMs: number;
  48→  enabled: boolean;
  49→  provider: "openai" | "cerebras" | "deterministic";
  50→  model: string;
  51→  disabledReason?: string;
  52→  openai?: {
  53→    apiKey: string;
  54→    apiBaseUrl: string;
  55→  };
  56→  cerebras?: {
  57→    apiKey: string;
  58→    apiBaseUrl: string;
  59→    maxCompletionTokens: number;
  60→    reasoningEffort: "none" | "low" | "medium" | "high";
  61→  };
  62→};
  63→
  64→type RepairSuccess = {
  65→  ok: true;
  66→  index: number;
  67→  message: StructuredSnapshotMessage;
  68→};
  69→
  70→type RepairFailure = {
  71→  ok: false;
  72→  index: number;
  73→  reason: string;
  74→};
  75→
  76→type RepairResult = RepairSuccess | RepairFailure;
  77→
  78→function readPositiveInteger(value: string | undefined, fallback: number) {
  79→  const parsed = Number(value);
  80→
  81→  if (!Number.isFinite(parsed)) {
  82→    return fallback;
  83→  }
  84→
  85→  return Math.max(1, Math.floor(parsed));
  86→}
  87→
  88→function readProviderSelection() {
  89→  const rawValue = process.env.STRUCTURING_PROVIDER?.trim().toLowerCase();
  90→
  91→  if (
  92→    rawValue === "openai" ||
  93→    rawValue === "cerebras" ||
  94→    rawValue === "deterministic"
  95→  ) {
  96→    return rawValue;
  97→  }
  98→
  99→  return "auto";
 100→}
 101→
 102→function readReasoningEffort(value: string | undefined) {
 103→  switch (value?.trim().toLowerCase()) {
 104→    case "none":
 105→    case "low":
 106→    case "medium":
 107→    case "high":
 108→      return value.trim().toLowerCase() as "none" | "low" | "medium" | "high";
 109→    default:
 110→      return DEFAULT_CEREBRAS_REASONING_EFFORT as "low";
 111→  }
 112→}
 113→
 114→function readStructuringConfig(): StructuringConfig {
 115→  const apiKey = process.env.OPENAI_API_KEY?.trim();
 116→  const cerebrasApiKey = process.env.CEREBRAS_API_KEY?.trim();
 117→  const rawEnabled =
 118→    process.env.STRUCTURING_ENABLED?.trim().toLowerCase() ??
 119→    process.env.OPENAI_STRUCTURING_ENABLED?.trim().toLowerCase();
 120→  const explicitlyDisabled =
 121→    rawEnabled === "0" || rawEnabled === "false" || rawEnabled === "off";
 122→  const providerSelection = readProviderSelection();
 123→  const openAiModel =
 124→    process.env.OPENAI_STRUCTURING_MODEL?.trim() || DEFAULT_MODEL;
 125→  const cerebrasModel =
 126→    process.env.CEREBRAS_STRUCTURING_MODEL?.trim() || DEFAULT_CEREBRAS_MODEL;
 127→  const openAiApiBaseUrl =
 128→    process.env.OPENAI_API_BASE_URL?.trim().replace(/\/+$/, "") ||
 129→    DEFAULT_API_BASE_URL;
 130→  const cerebrasApiBaseUrl =
 131→    process.env.CEREBRAS_API_BASE_URL?.trim().replace(/\/+$/, "") ||
 132→    DEFAULT_CEREBRAS_API_BASE_URL;
 133→  const sharedConfig = {
 134→    concurrency: readPositiveInteger(
 135→      process.env.STRUCTURING_CONCURRENCY ??
 136→        process.env.OPENAI_STRUCTURING_CONCURRENCY,
 137→      DEFAULT_CONCURRENCY,
 138→    ),
 139→    maxMessages: readPositiveInteger(
 140→      process.env.STRUCTURING_MAX_MESSAGES ??
 141→        process.env.OPENAI_STRUCTURING_MAX_MESSAGES,
 142→      DEFAULT_MAX_MESSAGES,
 143→    ),
 144→    maxMessageChars: readPositiveInteger(
 145→      process.env.STRUCTURING_MAX_MESSAGE_CHARS ??
 146→        process.env.OPENAI_STRUCTURING_MAX_MESSAGE_CHARS,
 147→      DEFAULT_MAX_MESSAGE_CHARS,
 148→    ),
 149→    timeoutMs: readPositiveInteger(
 150→      process.env.STRUCTURING_TIMEOUT_MS ??
 151→        process.env.OPENAI_STRUCTURING_TIMEOUT_MS,
 152→      DEFAULT_TIMEOUT_MS,
 153→    ),
 154→  };
 155→
 156→  if (explicitlyDisabled) {
 157→    return {
 158→      ...sharedConfig,
 159→      enabled: false,
 160→      provider: "deterministic",
 161→      model: openAiModel,
 162→      disabledReason: "STRUCTURING_ENABLED is disabled.",
 163→    };
 164→  }
 165→
 166→  const selectedProvider =
 167→    providerSelection === "auto"
 168→      ? apiKey
 169→        ? "openai"
 170→        : cerebrasApiKey
 171→          ? "cerebras"
 172→          : "deterministic"
 173→      : providerSelection;
 174→
 175→  if (selectedProvider === "openai") {
 176→    return {
 177→      ...sharedConfig,
 178→      enabled: Boolean(apiKey),
 179→      provider: "openai",
 180→      model: openAiModel,
 181→      disabledReason: apiKey ? undefined : "OPENAI_API_KEY is not configured.",
 182→      openai: apiKey
 183→        ? {
 184→            apiKey,
 185→            apiBaseUrl: openAiApiBaseUrl,
 186→          }
 187→        : undefined,
 188→    };
 189→  }
 190→
 191→  if (selectedProvider === "cerebras") {
 192→    return {
 193→      ...sharedConfig,
 194→      enabled: Boolean(cerebrasApiKey),
 195→      provider: "cerebras",
 196→      model: cerebrasModel,
 197→      disabledReason: cerebrasApiKey
 198→        ? undefined
 199→        : "CEREBRAS_API_KEY is not configured.",
 200→      cerebras: cerebrasApiKey
 201→        ? {
 202→            apiKey: cerebrasApiKey,
 203→            apiBaseUrl: cerebrasApiBaseUrl,
 204→            maxCompletionTokens: readPositiveInteger(
 205→              process.env.CEREBRAS_STRUCTURING_MAX_COMPLETION_TOKENS,
 206→              DEFAULT_CEREBRAS_MAX_COMPLETION_TOKENS,
 207→            ),
 208→            reasoningEffort: readReasoningEffort(
 209→              process.env.CEREBRAS_STRUCTURING_REASONING_EFFORT,
 210→            ),
 211→          }
 212→        : undefined,
 213→    };
 214→  }
 215→
 216→  return {
 217→    ...sharedConfig,
 218→    enabled: false,
 219→    provider: "deterministic",
 220→    model: openAiModel,
 221→    disabledReason: "No structuring provider key is configured.",
 222→  };
 223→}
 224→
 225→function defaultParserStrategy(message: NormalizedSnapshotMessage) {
 226→  const parser = message.parser ?? {};
 227→
 228→  return {
 229→    ...parser,
 230→    blockCount: parser.blockCount ?? message.blocks.length,
 231→    strategy:
 232→      parser.strategy ?? (parser.usedFallback ? "fallback" : "deterministic"),
 233→  } satisfies NonNullable<NormalizedSnapshotMessage["parser"]>;
 234→}
 235→
 236→function normalizeMessages(
 237→  messages: NormalizedSnapshotPayload["messages"],
 238→): StructuredSnapshotMessage[] {
 239→  return messages.map((message) => ({
 240→    ...message,
 241→    parser: defaultParserStrategy(message),
 242→  }));
 243→}
 244→
 245→function countMatches(value: string, pattern: RegExp) {
 246→  const flags = pattern.flags.includes("g")
 247→    ? pattern.flags
 248→    : `${pattern.flags}g`;
 249→  return Array.from(value.matchAll(new RegExp(pattern.source, flags))).length;
 250→}
 251→
 252→function collectParagraphRepairSignals(message: StructuredSnapshotMessage) {
 253→  const signals: Array<{
 254→    blockIndex: number;
 255→    reasons: string[];
 256→    score: number;
 257→  }> = [];
 258→
 259→  for (const [blockIndex, block] of message.blocks.entries()) {
 260→    if (block.type !== "paragraph" && block.type !== "quote") {
 261→      continue;
 262→    }
 263→
 264→    const reasons = new Set<string>();
 265→    let score = 0;
 266→
 267→    if (countMatches(block.text, EMPHASIZED_STEP_PATTERN) >= 2) {
 268→      reasons.add("markdown-step-paragraph");
 269→      score += 4;
 270→    }
 271→
 272→    const syntaxMatches = countMatches(
 273→      block.text,
 274→      PARAGRAPH_BLOCK_SYNTAX_PATTERN,
 275→    );
 276→
 277→    if (syntaxMatches >= 2 && block.text.includes("\n")) {
 278→      reasons.add("block-markdown-leaked-into-paragraph");
 279→      score += 4;
 280→    }
 281→
 282→    if (block.text.includes("```")) {
 283→      reasons.add("code-fence-leaked-into-paragraph");
 284→      score += 5;
 285→    }
 286→
 287→    if (countMatches(block.text, /\|.+\|/gm) >= 2) {
 288→      reasons.add("table-markup-leaked-into-paragraph");
 289→      score += 5;
 290→    }
 291→
 292→    if (score < MIN_REPAIR_SCORE) {
 293→      continue;
 294→    }
 295→
 296→    signals.push({
 297→      blockIndex,
 298→      reasons: [...reasons],
 299→      score,
 300→    });
 301→  }
 302→
 303→  return signals;
 304→}
 305→
 306→function collectRawHtmlRepairSignals(message: StructuredSnapshotMessage) {
 307→  const reasons = new Set<string>();
 308→  let score = 0;
 309→
 310→  const hasCodeBlock = message.blocks.some((block) => block.type === "code");
 311→  const hasTableBlock = message.blocks.some((block) => block.type === "table");
 312→  const hasListBlock = message.blocks.some((block) => block.type === "list");
 313→  const hasQuoteBlock = message.blocks.some((block) => block.type === "quote");
 314→
 315→  if (message.rawHtml?.includes("<pre") && !hasCodeBlock) {
 316→    reasons.add("raw-html-code-missing-in-blocks");
 317→    score += 5;
 318→  }
 319→
 320→  if (message.rawHtml?.includes("<table") && !hasTableBlock) {
 321→    reasons.add("raw-html-table-missing-in-blocks");
 322→    score += 5;
 323→  }
 324→
 325→  if (
 326→    (message.rawHtml?.includes("<ul") || message.rawHtml?.includes("<ol")) &&
 327→    !hasListBlock
 328→  ) {
 329→    reasons.add("raw-html-list-missing-in-blocks");
 330→    score += 4;
 331→  }
 332→
 333→  if (message.rawHtml?.includes("<blockquote") && !hasQuoteBlock) {
 334→    reasons.add("raw-html-quote-missing-in-blocks");
 335→    score += 4;
 336→  }
 337→
 338→  return {
 339→    reasons: [...reasons],
 340→    score,
 341→  };
 342→}
 343→
 344→function detectMessageRepairCandidate(message: StructuredSnapshotMessage) {
 345→  if (message.role !== "assistant" || !message.rawText?.trim()) {
 346→    return null;
 347→  }
 348→
 349→  const reasons = new Set<string>();
 350→  let score = 0;
 351→
 352→  if (message.parser.usedFallback) {
 353→    reasons.add("fallback");
 354→    score += 8;
 355→  }
 356→
 357→  if (
 358→    message.blocks.length === 1 &&
 359→    message.blocks[0]?.type === "paragraph" &&
 360→    (STRUCTURE_HINT_PATTERN.test(message.rawText) ||
 361→      message.rawHtml?.includes("<pre") ||
 362→      message.rawHtml?.includes("<table") ||
 363→      message.rawHtml?.includes("<ul") ||
 364→      message.rawHtml?.includes("<ol") ||
 365→      message.rawHtml?.includes("<blockquote"))
 366→  ) {
 367→    reasons.add("single-paragraph-structure-hints");
 368→    score += 6;
 369→  }
 370→
 371→  const rawHtmlSignals = collectRawHtmlRepairSignals(message);
 372→
 373→  for (const reason of rawHtmlSignals.reasons) {
 374→    reasons.add(reason);
 375→  }
 376→
 377→  score += rawHtmlSignals.score;
 378→
 379→  if (score < MIN_REPAIR_SCORE) {
 380→    return null;
 381→  }
 382→
 383→  return {
 384→    reasons: [...reasons],
 385→    score,
 386→  };
 387→}
 388→
 389→function blockToPlainText(block: Block) {
 390→  switch (block.type) {
 391→    case "paragraph":
 392→    case "heading":
 393→    case "quote":
 394→    case "code":
 395→      return block.text;
 396→    case "list":
 397→      return block.items.join("\n");
 398→    case "table":
 399→      return [
 400→        block.headers.join(" | "),
 401→        ...block.rows.map((row) => row.join(" | ")),
 402→      ].join("\n");
 403→  }
 404→}
 405→
 406→function normalizeComparisonText(value: string) {
 407→  return value
 408→    .replace(/\u00a0/g, " ")
 409→    .replace(/\r/g, "")
 410→    .replace(/[|`>#*_~-]/g, " ")
 411→    .replace(/\s+/g, " ")
 412→    .trim()
 413→    .toLowerCase();
 414→}
 415→
 416→function contentLooksPreserved(rawText: string, blocks: Block[]) {
 417→  const original = normalizeComparisonText(rawText);
 418→  const candidate = normalizeComparisonText(
 419→    blocks.map(blockToPlainText).join("\n"),
 420→  );
 421→
 422→  if (!original) {
 423→    return candidate.length === 0;
 424→  }
 425→
 426→  if (!candidate) {
 427→    return false;
 428→  }
 429→
 430→  const ratio = candidate.length / original.length;
 431→  return ratio >= 0.45 && ratio <= 1.8;
 432→}
 433→
 434→function parseStructuredBlocks(payload: unknown) {
 435→  if (!payload || typeof payload !== "object" || !("blocks" in payload)) {
 436→    throw new Error("Structured response did not contain a blocks array.");
 437→  }
 438→
 439→  const blocksValue = (payload as { blocks?: unknown }).blocks;
 440→
 441→  if (!Array.isArray(blocksValue) || blocksValue.length === 0) {
 442→    throw new Error("Structured response returned no blocks.");
 443→  }
 444→
 445→  const blocks: Block[] = [];
 446→
 447→  for (const block of blocksValue) {
 448→    const parsed = blockSchema.safeParse(block);
 449→
 450→    if (!parsed.success) {
 451→      throw new Error("Structured response returned an invalid block.");
 452→    }
 453→
 454→    blocks.push(parsed.data);
 455→  }
 456→
 457→  return blocks;
 458→}
 459→
 460→function getOutputText(payload: unknown) {
 461→  if (payload && typeof payload === "object" && "output_text" in payload) {
 462→    const outputText = (payload as { output_text?: unknown }).output_text;
 463→    if (typeof outputText === "string" && outputText.trim()) {
 464→      return outputText;
 465→    }
 466→  }
 467→
 468→  if (!payload || typeof payload !== "object" || !("output" in payload)) {
 469→    throw new Error("Responses API payload did not include output text.");
 470→  }
 471→
 472→  const output = (payload as { output?: unknown }).output;
 473→
 474→  if (!Array.isArray(output)) {
 475→    throw new Error("Responses API payload did not include output items.");
 476→  }
 477→
 478→  const text = output
 479→    .flatMap((item) => {
 480→      if (!item || typeof item !== "object" || !("content" in item)) {
 481→        return [];
 482→      }
 483→
 484→      const content = (item as { content?: unknown }).content;
 485→      if (!Array.isArray(content)) {
 486→        return [];
 487→      }
 488→
 489→      return content.flatMap((entry) => {
 490→        if (!entry || typeof entry !== "object") {
 491→          return [];
 492→        }
 493→
 494→        const maybeText = (entry as { text?: unknown }).text;
 495→        return typeof maybeText === "string" && maybeText.trim()
 496→          ? [maybeText]
 497→          : [];
 498→      });
 499→    })
 500→    .join("\n")
 501→    .trim();
 502→
 503→  if (!text) {
 504→    throw new Error(
 505→      "Responses API payload did not contain structured JSON text.",
 506→    );
 507→  }
 508→
 509→  return text;
 510→}
 511→
 512→function buildSchema() {
 513→  return {
 514→    type: "object",
 515→    additionalProperties: false,
 516→    required: ["blocks"],
 517→    properties: {
 518→      blocks: {
 519→        type: "array",
 520→        items: {
 521→          anyOf: [
 522→            {
 523→              type: "object",
 524→              additionalProperties: false,
 525→              required: ["type", "text"],
 526→              properties: {
 527→                type: { type: "string", enum: ["paragraph"] },
 528→                text: { type: "string" },
 529→              },
 530→            },
 531→            {
 532→              type: "object",
 533→              additionalProperties: false,
 534→              required: ["type", "level", "text"],
 535→              properties: {
 536→                type: { type: "string", enum: ["heading"] },
 537→                level: { type: "integer", minimum: 1, maximum: 6 },
 538→                text: { type: "string" },
 539→              },
 540→            },
 541→            {
 542→              type: "object",
 543→              additionalProperties: false,
 544→              required: ["type", "ordered", "items"],
 545→              properties: {
 546→                type: { type: "string", enum: ["list"] },
 547→                ordered: { type: "boolean" },
 548→                items: {
 549→                  type: "array",
 550→                  items: { type: "string" },
 551→                },
 552→              },
 553→            },
 554→            {
 555→              type: "object",
 556→              additionalProperties: false,
 557→              required: ["type", "language", "text"],
 558→              properties: {
 559→                type: { type: "string", enum: ["code"] },
 560→                language: { type: "string" },
 561→                text: { type: "string" },
 562→              },
 563→            },
 564→            {
 565→              type: "object",
 566→              additionalProperties: false,
 567→              required: ["type", "text"],
 568→              properties: {
 569→                type: { type: "string", enum: ["quote"] },
 570→                text: { type: "string" },
 571→              },
 572→            },
 573→            {
 574→              type: "object",
 575→              additionalProperties: false,
 576→              required: ["type", "headers", "rows"],
 577→              properties: {
 578→                type: { type: "string", enum: ["table"] },
 579→                headers: {
 580→                  type: "array",
 581→                  items: { type: "string" },
 582→                },
 583→                rows: {
 584→                  type: "array",
 585→                  items: {
 586→                    type: "array",
 587→                    items: { type: "string" },
 588→                  },
 589→                },
 590→              },
 591→            },
 592→          ],
 593→        },
 594→      },
 595→    },
 596→  } as const;
 597→}
 598→
 599→function excerptAround(
 600→  value: string | undefined,
 601→  needle: string,
 602→  radius: number,
 603→) {
 604→  if (!value?.trim()) {
 605→    return undefined;
 606→  }
 607→
 608→  const normalizedNeedle = needle.trim();
 609→  if (!normalizedNeedle) {
 610→    return value.slice(0, radius * 2);
 611→  }
 612→
 613→  const searchNeedle = normalizedNeedle.slice(0, 96);
 614→  const matchIndex = value.indexOf(searchNeedle);
 615→
 616→  if (matchIndex < 0) {
 617→    return value.slice(0, radius * 2);
 618→  }
 619→
 620→  const start = Math.max(0, matchIndex - radius);
 621→  const end = Math.min(value.length, matchIndex + searchNeedle.length + radius);
 622→  return value.slice(start, end);
 623→}
 624→
 625→function candidateInputSize(candidate: CandidateMessage) {
 626→  if (candidate.kind === "block") {
 627→    const block = candidate.message.blocks[candidate.blockIndex ?? 0];
 628→    return block ? blockToPlainText(block).length : 0;
 629→  }
 630→
 631→  return candidate.message.rawText?.length ?? 0;
 632→}
 633→
 634→function buildPrompt(candidate: CandidateMessage) {
 635→  if (candidate.kind === "block") {
 636→    const blockIndex = candidate.blockIndex ?? 0;
 637→    const block = candidate.message.blocks[blockIndex];
 638→
 639→    return JSON.stringify(
 640→      {
 641→        scope: "single-block-repair",
 642→        role: candidate.message.role,
 643→        reasons: candidate.reasons,
 644→        score: candidate.score,
 645→        blockIndex,
 646→        currentBlock: block,
 647→        previousBlock:
 648→          blockIndex > 0 ? candidate.message.blocks[blockIndex - 1] : null,
 649→        nextBlock:
 650→          blockIndex < candidate.message.blocks.length - 1
 651→            ? candidate.message.blocks[blockIndex + 1]
 652→            : null,
 653→        rawTextExcerpt: block
 654→          ? excerptAround(
 655→              candidate.message.rawText,
 656→              blockToPlainText(block),
 657→              900,
 658→            )
 659→          : candidate.message.rawText?.slice(0, 1_800),
 660→      },
 661→      null,
 662→      2,
 663→    );
 664→  }
 665→
 666→  return JSON.stringify(
 667→    {
 668→      scope: "full-message-repair",
 669→      role: candidate.message.role,
 670→      reasons: candidate.reasons,
 671→      score: candidate.score,
 672→      rawText: candidate.message.rawText,
 673→      rawHtml: candidate.message.rawHtml?.slice(0, 8_000),
 674→      currentBlocks: candidate.message.blocks,
 675→    },
 676→    null,
 677→    2,
 678→  );
 679→}
 680→
 681→async function requestRepair(
 682→  candidate: CandidateMessage,
 683→  config: StructuringConfig,
 684→) {
 685→  if (config.provider === "openai" && config.openai) {
 686→    return requestOpenAiRepair(candidate, config);
 687→  }
 688→
 689→  if (config.provider === "cerebras" && config.cerebras) {
 690→    return requestCerebrasRepair(candidate, config);
 691→  }
 692→
 693→  throw new Error("No active AI provider is configured for structuring.");
 694→}
 695→
 696→async function requestOpenAiRepair(
 697→  candidate: CandidateMessage,
 698→  config: StructuringConfig,
 699→) {
 700→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
 701→    method: "POST",
 702→    headers: {
 703→      "Content-Type": "application/json",
 704→      Authorization: `Bearer ${config.openai?.apiKey}`,
 705→    },
 706→    body: JSON.stringify({
 707→      model: config.model,
 708→      reasoning: {
 709→        effort: "minimal",
 710→      },
 711→      input: [
 712→        {
 713→          role: "system",
 714→          content: [
 715→            {
 716→              type: "input_text",
 717→              text:
 718→                candidate.kind === "block"
