 827→async function repairCandidate(
 828→  candidate: CandidateMessage,
 829→  config: StructuringConfig,
 830→): Promise<RepairResult> {
 831→  try {
 832→    const repairedBlocks = await requestRepair(candidate, config);
 833→
 834→    const comparisonSource =
 835→      candidate.kind === "block"
 836→        ? blockToPlainText(candidate.message.blocks[candidate.blockIndex ?? 0]!)
 837→        : (candidate.message.rawText ?? "");
 838→
 839→    if (!contentLooksPreserved(comparisonSource, repairedBlocks)) {
 840→      return {
 841→        ok: false,
 842→        index: candidate.index,
 843→        reason:
 844→          "AI repair changed the message too aggressively and was rejected.",
 845→      };
 846→    }
 847→
 848→    const nextBlocks =
 849→      candidate.kind === "block"
 850→        ? [
 851→            ...candidate.message.blocks.slice(0, candidate.blockIndex),
 852→            ...repairedBlocks,
 853→            ...candidate.message.blocks.slice((candidate.blockIndex ?? 0) + 1),
 854→          ]
 855→        : repairedBlocks;
 856→
 857→    return {
 858→      ok: true,
 859→      index: candidate.index,
 860→      message: {
 861→        ...candidate.message,
 862→        blocks: nextBlocks,
 863→        parser: {
 864→          ...defaultParserStrategy(candidate.message),
 865→          blockCount: nextBlocks.length,
 866→          usedFallback: false,
 867→          strategy: "ai-repair",
 868→          model: config.model,
 869→        },
 870→      },
 871→    };
 872→  } catch (error) {
 873→    return {
 874→      ok: false,
 875→      index: candidate.index,
 876→      reason:
 877→        error instanceof Error
 878→          ? error.message
 879→          : "AI repair failed before a structured result could be validated.",
 880→    };
 881→  }
 882→}
