 884→async function mapWithConcurrency<T, TResult>(
 885→  items: T[],
 886→  concurrency: number,
 887→  mapper: (item: T) => Promise<TResult>,
 888→) {
 889→  const results: TResult[] = new Array(items.length);
 890→  let nextIndex = 0;
 891→
 892→  async function worker() {
 893→    while (nextIndex < items.length) {
 894→      const currentIndex = nextIndex;
 895→      nextIndex += 1;
 896→      results[currentIndex] = await mapper(items[currentIndex]!);
 897→    }
 898→  }
 899→
 900→  await Promise.all(
 901→    Array.from({ length: Math.min(concurrency, items.length) }, () => worker()),
 902→  );
 903→
 904→  return results;
 905→}
