 907→export async function applyOpenAiStructuring(
 908→  messages: NormalizedSnapshotPayload["messages"],
 909→): Promise<{
 910→  messages: NormalizedSnapshotPayload["messages"];
 911→  warnings: string[];
 912→  structuring: StructuringMetadata;
 913→}> {
 914→  const normalizedMessages = normalizeMessages(messages);
 915→  const candidateMessages: CandidateMessage[] = normalizedMessages
 916→    .flatMap<CandidateMessage>((message, index) => {
 917→      const messageLevelCandidate = detectMessageRepairCandidate(message);
 918→
 919→      if (messageLevelCandidate) {
 920→        return [
 921→          {
 922→            kind: "message" as const,
 923→            index,
 924→            message,
 925→            reasons: messageLevelCandidate.reasons,
 926→            score: messageLevelCandidate.score,
 927→          },
 928→        ];
 929→      }
 930→
 931→      const bestParagraphCandidate = collectParagraphRepairSignals(
 932→        message,
 933→      ).sort(
 934→        (left, right) =>
 935→          right.score - left.score || left.blockIndex - right.blockIndex,
 936→      )[0];
 937→
 938→      return bestParagraphCandidate
 939→        ? [
 940→            {
 941→              kind: "block" as const,
 942→              index,
 943→              message,
 944→              reasons: bestParagraphCandidate.reasons,
 945→              score: bestParagraphCandidate.score,
 946→              blockIndex: bestParagraphCandidate.blockIndex,
 947→            },
 948→          ]
 949→        : [];
 950→    })
 951→    .sort(
 952→      (left, right) => right.score - left.score || left.index - right.index,
 953→    );
 954→
 955→  if (candidateMessages.length === 0) {
 956→    return {
 957→      messages: normalizedMessages,
 958→      warnings: [],
 959→      structuring: {
 960→        status: "skipped",
 961→        provider: "deterministic",
 962→        candidateCount: 0,
 963→        attemptedCount: 0,
 964→        repairedCount: 0,
 965→        failedCount: 0,
 966→        skippedCount: 0,
 967→        skippedReason:
 968→          "No low-confidence assistant messages required AI repair.",
 969→      },
 970→    };
 971→  }
 972→
 973→  const config = readStructuringConfig();
 974→
 975→  if (!config.enabled) {
 976→    return {
 977→      messages: normalizedMessages,
 978→      warnings: [],
 979→      structuring: {
 980→        status: "disabled",
 981→        provider: config.provider,
 982→        model: config.model,
 983→        candidateCount: candidateMessages.length,
 984→        attemptedCount: 0,
 985→        repairedCount: 0,
 986→        failedCount: 0,
 987→        skippedCount: candidateMessages.length,
 988→        skippedReason: config.disabledReason,
 989→      },
 990→    };
 991→  }
 992→
 993→  const eligibleCandidates = candidateMessages.filter(
 994→    (candidate) => candidateInputSize(candidate) <= config.maxMessageChars,
 995→  );
 996→  const oversizedCount = candidateMessages.length - eligibleCandidates.length;
 997→  const attemptedCandidates = eligibleCandidates.slice(0, config.maxMessages);
 998→  const cappedCount = Math.max(
 999→    0,
1000→    eligibleCandidates.length - attemptedCandidates.length,
1001→  );
1002→
1003→  if (attemptedCandidates.length === 0) {
1004→    const skippedReason =
1005→      oversizedCount > 0
1006→        ? `All low-confidence assistant messages exceeded the ${config.maxMessageChars}-character repair limit.`
1007→        : "No assistant messages remained eligible for AI repair.";
1008→
1009→    return {
1010→      messages: normalizedMessages,
1011→      warnings:
1012→        oversizedCount > 0
1013→          ? [
1014→              `Skipped AI repair for ${oversizedCount} assistant message(s) because they exceeded the raw text size limit.`,
1015→            ]
1016→          : [],
1017→      structuring: {
1018→        status: "skipped",
1019→        provider: config.provider,
1020→        model: config.model,
1021→        candidateCount: candidateMessages.length,
1022→        attemptedCount: 0,
1023→        repairedCount: 0,
1024→        failedCount: 0,
1025→        skippedCount: candidateMessages.length,
1026→        skippedReason,
1027→      },
1028→    };
1029→  }
1030→
1031→  const repairs = await mapWithConcurrency(
1032→    attemptedCandidates,
1033→    config.concurrency,
1034→    (candidate) => repairCandidate(candidate, config),
1035→  );
1036→
1037→  const nextMessages = [...normalizedMessages];
1038→  const failureReasons = new Set<string>();
1039→  let repairedCount = 0;
1040→  let failedCount = 0;
1041→
1042→  for (const repair of repairs) {
1043→    if (repair.ok) {
1044→      nextMessages[repair.index] = repair.message;
1045→      repairedCount += 1;
1046→      continue;
1047→    }
1048→
1049→    failedCount += 1;
1050→    failureReasons.add(repair.reason);
1051→  }
1052→
1053→  const warnings: string[] = [];
1054→
1055→  if (oversizedCount > 0) {
1056→    warnings.push(
1057→      `Skipped AI repair for ${oversizedCount} assistant message(s) because they exceeded the raw text size limit.`,
1058→    );
1059→  }
1060→
1061→  if (cappedCount > 0) {
1062→    warnings.push(
1063→      `Skipped AI repair for ${cappedCount} assistant message(s) because the STRUCTURING_MAX_MESSAGES limit was reached.`,
1064→    );
1065→  }
1066→
1067→  if (failedCount > 0) {
1068→    warnings.push(
1069→      `AI repair failed for ${failedCount} assistant message(s). Deterministic blocks were kept.`,
1070→    );
1071→  }
1072→
1073→  for (const failureReason of failureReasons) {
1074→    warnings.push(`AI repair detail: ${failureReason}`);
1075→  }
1076→
1077→  const status =
1078→    repairedCount === 0 && failedCount > 0
1079→      ? "failed"
1080→      : failedCount > 0
1081→        ? "partial"
1082→        : "applied";
1083→
1084→  return {
1085→    messages: nextMessages,
1086→    warnings,
1087→    structuring: {
1088→      status,
1089→      provider: config.provider,
1090→      model: config.model,
1091→      candidateCount: candidateMessages.length,
1092→      attemptedCount: attemptedCandidates.length,
1093→      repairedCount,
1094→      failedCount,
1095→      skippedCount: oversizedCount + cappedCount,
1096→      skippedReason:
1097→        oversizedCount + cappedCount > 0
1098→          ? "Some candidates were skipped before repair."
1099→          : undefined,
1100→    },
1101→  };
1102→}
