  1→import type {
  2→  Block,
  3→  CompoundContextSibling,
  4→  CompoundSelector,
  5→  Conversation,
  6→  FormatRule,
  7→} from "@chat-exporter/shared";
  8→import { ruleSelectorSchema } from "@chat-exporter/shared";
  9→
 10→import { blockToPlainText } from "./reader-block-render";
 11→
 12→export type ReaderMatchContext = {
 13→  messageRole: string;
 14→  blocks: Block[];
 15→};
 16→
 17→export function matchesReaderRule(
 18→  rule: FormatRule,
 19→  messageId: string,
 20→  blockIndex: number,
 21→  blockType: Block["type"],
 22→  blockText: string,
 23→  context?: ReaderMatchContext,
 24→  blockId?: string,
 25→) {
 26→  const parsed = ruleSelectorSchema.safeParse(rule.selector);
 27→
 28→  if (!parsed.success) {
 29→    return false;
 30→  }
 31→
 32→  const selector = parsed.data;
 33→
 34→  if ("strategy" in selector && selector.strategy === "compound") {
 35→    return matchesCompoundSelector(
 36→      selector,
 37→      blockType,
 38→      blockText,
 39→      blockIndex,
 40→      context,
 41→    );
 42→  }
 43→
 44→  if ("strategy" in selector && selector.strategy === "block_type") {
 45→    return selector.blockType === blockType;
 46→  }
 47→
 48→  if ("strategy" in selector && selector.strategy === "prefix_before_colon") {
 49→    return (
 50→      "blockType" in selector &&
 51→      selector.blockType === blockType &&
 52→      /^([^:\n]{1,120}:)(\s*)(.*)$/.test(blockText)
 53→    );
 54→  }
 55→
 56→  // exact match (strategy === "exact")
 57→  // Prefer blockId match when available; fall back to blockIndex for legacy rules
 58→  const blockMatch =
 59→    "blockId" in selector && selector.blockId && blockId
 60→      ? selector.blockId === blockId
 61→      : "blockIndex" in selector && selector.blockIndex === blockIndex;
 62→
 63→  return (
 64→    "messageId" in selector &&
 65→    selector.messageId === messageId &&
 66→    blockMatch &&
 67→    "blockType" in selector &&
 68→    selector.blockType === blockType
 69→  );
 70→}
 71→
 72→function matchesCompoundSelector(
 73→  selector: CompoundSelector,
 74→  blockType: Block["type"],
 75→  blockText: string,
 76→  blockIndex: number,
 77→  context?: ReaderMatchContext,
 78→): boolean {
 79→  if (selector.blockType !== undefined && selector.blockType !== blockType) {
 80→    return false;
 81→  }
 82→
 83→  if (selector.messageRole !== undefined) {
 84→    if (context === undefined || selector.messageRole !== context.messageRole) {
 85→      return false;
 86→    }
 87→  }
 88→
 89→  if (selector.headingLevel !== undefined) {
 90→    if (blockType !== "heading") {
 91→      return false;
 92→    }
 93→    if (context !== undefined) {
 94→      const block = context.blocks[blockIndex];
 95→      if (
 96→        block === undefined ||
 97→        block.type !== "heading" ||
 98→        block.level !== selector.headingLevel
 99→      ) {
100→        return false;
101→      }
102→    }
103→  }
104→
105→  if (selector.position !== undefined && context !== undefined) {
106→    if (selector.position === "first" && blockIndex !== 0) {
107→      return false;
108→    }
109→    if (
110→      selector.position === "last" &&
111→      blockIndex !== context.blocks.length - 1
112→    ) {
113→      return false;
114→    }
115→  }
116→
117→  if (selector.textPattern !== undefined) {
118→    if (!matchesTextPattern(blockText, selector.textPattern)) {
119→      return false;
120→    }
121→  }
122→
123→  if (selector.context !== undefined && context !== undefined) {
124→    if (selector.context.previousSibling !== undefined) {
125→      const prevBlock = context.blocks[blockIndex - 1];
126→      if (!matchesSiblingFilter(prevBlock, selector.context.previousSibling)) {
127→        return false;
128→      }
129→    }
130→
131→    if (selector.context.nextSibling !== undefined) {
132→      const nextBlock = context.blocks[blockIndex + 1];
133→      if (!matchesSiblingFilter(nextBlock, selector.context.nextSibling)) {
134→        return false;
135→      }
136→    }
137→  }
138→
139→  return true;
140→}
141→
142→function matchesTextPattern(text: string, pattern: string): boolean {
143→  try {
144→    return new RegExp(pattern).test(text);
145→  } catch {
146→    return false;
147→  }
148→}
149→
150→function matchesSiblingFilter(
151→  block: Block | undefined,
152→  filter: CompoundContextSibling,
153→): boolean {
154→  if (block === undefined) {
155→    return false;
156→  }
157→
158→  if (filter.blockType !== undefined && block.type !== filter.blockType) {
159→    return false;
160→  }
161→
162→  if (filter.headingLevel !== undefined) {
163→    if (block.type !== "heading" || block.level !== filter.headingLevel) {
164→      return false;
165→    }
166→  }
167→
168→  if (filter.textPattern !== undefined) {
169→    const text =
170→      block.type === "list"
171→        ? block.items.join("\n")
172→        : block.type === "table"
173→          ? [
174→              block.headers.join(" | "),
175→              ...block.rows.map((row) => row.join(" | ")),
176→            ].join("\n")
177→          : block.text;
178→
179→    if (!matchesTextPattern(text, filter.textPattern)) {
180→      return false;
181→    }
182→  }
183→
184→  return true;
185→}
186→
187→export function getBlocksMatchingRule(
188→  rule: FormatRule,
189→  conversation: Conversation,
190→): Array<{ messageId: string; blockIndex: number; blockId: string }> {
191→  const matches: Array<{
192→    messageId: string;
193→    blockIndex: number;
194→    blockId: string;
195→  }> = [];
196→
197→  for (const message of conversation.messages) {
198→    const context: ReaderMatchContext = {
199→      messageRole: message.role,
200→      blocks: message.blocks,
201→    };
202→
203→    for (
204→      let blockIndex = 0;
205→      blockIndex < message.blocks.length;
206→      blockIndex += 1
207→    ) {
208→      const block = message.blocks[blockIndex];
209→
210→      if (!block) {
211→        continue;
212→      }
213→
214→      if (
215→        matchesReaderRule(
216→          rule,
217→          message.id,
218→          blockIndex,
219→          block.type,
220→          blockToPlainText(block),
221→          context,
222→          block.id,
223→        )
224→      ) {
225→        matches.push({ messageId: message.id, blockIndex, blockId: block.id });
226→      }
227→    }
228→  }
229→
230→  return matches;
231→}
