156→export function renderReaderBlock(block: Block, effects: RuleEffect[]) {
157→  const custom = collectCustomStyles(effects);
158→  const textStyle = custom.textStyle as React.CSSProperties | undefined;
159→  const itemStyle = custom.itemStyle as React.CSSProperties | undefined;
160→
161→  switch (block.type) {
162→    case "paragraph": {
163→      const numberedBoldMatch = block.text.match(
164→        /^\*\*(\d+\.\s.+?)\*\*\s*([\s\S]*)$/,
165→      );
166→
167→      if (numberedBoldMatch) {
168→        const heading = numberedBoldMatch[1];
169→        const rest = numberedBoldMatch[2]?.trim();
170→
171→        return (
172→          <>
173→            <hr className="mt-8 border-border/40" />
174→            <h2
175→              className="mt-8 font-semibold text-foreground"
176→              style={textStyle}
177→            >
178→              {heading}
179→            </h2>
180→            {rest ? (
181→              <p
182→                className="text-sm leading-7 text-foreground/90"
183→                style={textStyle}
184→              >
185→                {renderReaderInlineText(rest, effects)}
186→              </p>
187→            ) : null}
188→          </>
189→        );
190→      }
191→
192→      return (
193→        <p className="text-sm leading-7 text-foreground/90" style={textStyle}>
194→          {renderReaderInlineText(block.text, effects)}
195→        </p>
196→      );
197→    }
198→    case "heading": {
199→      const level = custom.headingLevel ?? block.level;
200→      const Tag = `h${Math.min(level, 6)}` as keyof JSX.IntrinsicElements;
201→      return (
202→        <Tag className="font-semibold text-foreground" style={textStyle}>
203→          {renderReaderInlineText(block.text, effects)}
204→        </Tag>
205→      );
206→    }
207→    case "list":
208→      return (
209→        <ul
210→          className="list-disc space-y-2 pl-5 text-sm leading-7 text-foreground/90"
211→          style={textStyle}
212→        >
213→          {(block.items ?? []).map((item) => (
214→            <li key={item} style={itemStyle}>
215→              {renderReaderInlineText(item, effects)}
216→            </li>
217→          ))}
218→        </ul>
219→      );
220→    case "quote":
221→      return (
222→        <blockquote
223→          className="border-l-2 border-accent pl-4 text-sm italic leading-7 text-foreground/80"
224→          style={textStyle}
225→        >
226→          {renderReaderInlineText(block.text, effects)}
227→        </blockquote>
228→      );
229→    case "code":
230→      return (
231→        <div
232→          className="rounded-2xl border border-border/80 bg-zinc-950 p-4 text-sm text-zinc-100"
233→          style={textStyle}
234→        >
235→          <p className="mb-3 text-xs uppercase tracking-[0.22em] text-zinc-400">
236→            {block.language}
237→          </p>
238→          <pre className="overflow-x-auto whitespace-pre-wrap break-words font-mono">
239→            <code>{block.text}</code>
240→          </pre>
241→        </div>
242→      );
243→    case "table":
244→      return (
245→        <div className="overflow-x-auto rounded-2xl border border-border/80">
246→          <table className="min-w-full text-left text-sm" style={textStyle}>
247→            <thead className="bg-secondary/70 text-secondary-foreground">
248→              <tr>
249→                {block.headers.map((header) => (
250→                  <th key={header} className="px-4 py-3 font-medium">
251→                    {header}
252→                  </th>
253→                ))}
254→              </tr>
255→            </thead>
256→            <tbody>
257→              {block.rows.map((row) => (
258→                <tr key={row.join("-")} className="border-t border-border/80">
259→                  {row.map((cell) => (
260→                    <td
261→                      key={cell}
262→                      className="px-4 py-3 align-top text-muted-foreground"
263→                      style={itemStyle}
264→                    >
265→                      {cell}
266→                    </td>
267→                  ))}
268→                </tr>
269→              ))}
270→            </tbody>
271→          </table>
272→        </div>
273→      );
274→  }
275→}
