 5→/** Block image, media, and font requests to reduce bandwidth. */
 6→export async function blockNonEssentialResources(
 7→  context: BrowserContext,
 8→): Promise<void> {
 9→  await context.route("**/*", (route) => {
10→    const resourceType = route.request().resourceType();
11→    if (
12→      resourceType === "image" ||
13→      resourceType === "media" ||
14→      resourceType === "font"
15→    ) {
16→      return route.abort();
17→    }
18→    return route.continue();
19→  });
