31→export function truncateMessagesIfNeeded(
32→  payload: NormalizedSnapshotPayload,
33→  maxCount: number,
34→): NormalizedSnapshotPayload {
35→  if (payload.messages.length > maxCount) {
36→    const originalCount = payload.messages.length;
37→    payload.messages = payload.messages.slice(-maxCount);
38→    payload.warnings.push(
39→      `Nachrichtenlimit überschritten: ${originalCount} Nachrichten gefunden, auf die letzten ${maxCount} gekürzt.`,
40→    );
41→  }
42→  return payload;
43→}
