45→/** Validate raw HTML size against limit. Returns byte size. Throws if exceeded. */
46→export function validateRawHtmlSize(rawHtml: string, maxBytes: number): number {
47→  const rawHtmlBytes = Buffer.byteLength(rawHtml, "utf8");
48→  if (rawHtmlBytes > maxBytes) {
49→    const sizeMb = (rawHtmlBytes / (1024 * 1024)).toFixed(1);
50→    const limitMb = (maxBytes / (1024 * 1024)).toFixed(1);
51→    throw new Error(
52→      `HTML-Größe überschritten: ${sizeMb} MB (Limit: ${limitMb} MB).`,
53→    );
54→  }
55→  return rawHtmlBytes;
56→}
