 16→  blockIndex: number;
 17→  messageId: string;
 18→  onBlockChange: (
 19→    messageId: string,
 20→    blockIndex: number,
 21→    newBlock: Block,
 22→  ) => void;
 23→  children: React.ReactNode;
 24→}
