  9→export function useMessageEdits(importId: string, snapshotId?: string) {
 10→  const queryClient = useQueryClient();
 11→  const debounceTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(
 12→    new Map(),
 13→  );
 14→  // Ref tracks the latest snapshotId so that saveEdit/deleteEdit always read
 15→  // the current value, even when called from a stale closure (e.g. after
 16→  // ensureSnapshot() creates a new snapshot but before React re-renders).
 17→  const snapshotIdRef = useRef(snapshotId);
 18→  snapshotIdRef.current = snapshotId;
 19→  // pendingTimerCount triggers re-renders when debounce timers are added or
 20→  // removed so that hasPendingEdits reflects the current state synchronously.
 21→  const [pendingTimerCount, setPendingTimerCount] = useState(0);
 22→
 23→  // inFlightMutationCount tracks every active saveMutation.mutate() call
 24→  // individually. useMutation.isPending only reflects the LATEST mutate() call,
 25→  // so if two saves overlap (e.g. editing msg-1 and msg-2 rapidly), an older
 26→  // in-flight save is invisible to isPending once a newer one starts. The
 27→  // counter increments on each mutate() and decrements in onSettled, ensuring
 28→  // hasPendingEdits stays true until every in-flight call has settled.
 29→  const [inFlightMutationCount, setInFlightMutationCount] = useState(0);
 30→
 31→  const editsQuery = useQuery({
 32→    ...orpc.edits.listForSnapshot.queryOptions({
 33→      input: { snapshotId: snapshotId as string },
 34→    }),
 35→    enabled: !!snapshotId,
 36→  });
 37→
 38→  const invalidate = () =>
 39→    queryClient.invalidateQueries({
 40→      queryKey: orpc.edits.listForSnapshot.key(),
 41→    });
 42→
 43→  const saveMutation = useMutation(
 44→    orpc.edits.save.mutationOptions({
 45→      onSuccess: () => invalidate(),
 46→      onSettled: () => setInFlightMutationCount((c) => c - 1),
 47→    }),
 48→  );
 49→
 50→  const deleteMutation = useMutation(
 51→    orpc.edits.delete.mutationOptions({
 52→      onSuccess: () => invalidate(),
 53→    }),
 54→  );
 55→
 56→  const editedMessagesMap = useMemo(() => {
 57→    const map = new Map<string, Block[]>();
 58→    if (!editsQuery.data) return map;
 59→    for (const edit of editsQuery.data) {
 60→      map.set(edit.messageId, edit.editedBlocks);
 61→    }
 62→    return map;
 63→  }, [editsQuery.data]);
 64→
 65→  const saveEdit = useCallback(
 66→    (
 67→      messageId: string,
 68→      blocks: Block[],
 69→      annotation?: string,
 70→      snapshotIdOverride?: string,
 71→    ) => {
 72→      // Use explicit override (from ensureSnapshot result) or fall back to ref.
 73→      const currentSnapshotId = snapshotIdOverride ?? snapshotIdRef.current;
 74→      if (!currentSnapshotId) return;
 75→
 76→      const existing = debounceTimers.current.get(messageId);
 77→      if (existing) {
 78→        clearTimeout(existing);
 79→        // Timer is being replaced — count stays the same, no net change needed
 80→      } else {
 81→        // New timer being added
 82→        setPendingTimerCount((c) => c + 1);
 83→      }
 84→
 85→      const resolvedSnapshotId = snapshotIdOverride ?? snapshotIdRef.current;
 86→
 87→      const timer = setTimeout(() => {
 88→        // Use the resolved snapshot ID captured at schedule time, but fall back
 89→        // to the ref in case it was still undefined then and has since arrived.
 90→        const sid = resolvedSnapshotId ?? snapshotIdRef.current;
 91→        if (!sid) {
 92→          debounceTimers.current.delete(messageId);
 93→          setPendingTimerCount((c) => c - 1);
 94→          return;
 95→        }
 96→        debounceTimers.current.delete(messageId);
 97→        setPendingTimerCount((c) => c - 1);
 98→        setInFlightMutationCount((c) => c + 1);
 99→        saveMutation.mutate({
100→          importId,
101→          snapshotId: sid,
102→          messageId,
103→          editedBlocks: blocks,
104→          annotation,
105→        });
106→      }, DEBOUNCE_MS);
107→
108→      debounceTimers.current.set(messageId, timer);
109→    },
110→    [importId, saveMutation.mutate],
111→  );
112→
113→  const deleteEdit = useCallback(
114→    (messageId: string) => {
115→      const currentSnapshotId = snapshotIdRef.current;
116→      if (!currentSnapshotId) return;
117→
118→      // Cancel any pending debounced save for this message
119→      const existing = debounceTimers.current.get(messageId);
120→      if (existing) {
121→        clearTimeout(existing);
122→        debounceTimers.current.delete(messageId);
123→        setPendingTimerCount((c) => c - 1);
124→      }
125→
126→      return deleteMutation.mutateAsync({
127→        importId,
128→        snapshotId: currentSnapshotId,
129→        messageId,
130→      });
131→    },
132→    [importId, deleteMutation.mutateAsync],
133→  );
134→
135→  return {
136→    edits: editsQuery.data ?? [],
137→    editedMessagesMap,
138→    isLoading: editsQuery.isLoading,
139→    isSaving: saveMutation.isPending,
140→    isDeleting: deleteMutation.isPending,
141→    hasPendingEdits: pendingTimerCount > 0 || inFlightMutationCount > 0,
142→    saveEdit,
143→    deleteEdit,
144→  };
145→}
