  1→import type { Block } from "@chat-exporter/shared";
  2→import React, { useCallback, useEffect, useRef } from "react";
  3→import { cn } from "@/lib/utils";
  4→import { blockToPlainText } from "@/components/format-workspace/reader-block-render";
  5→
  6→/**
  7→ * Renders children only on initial mount — prevents React from reconciling
  8→ * DOM nodes that the browser's contentEditable engine has modified.
  9→ */
 10→const FrozenChildren = React.memo(
 11→  ({ children }: { children: React.ReactNode }) => <>{children}</>,
 12→  () => true,
 13→);
 14→
 15→interface EditableBlockProps {
 16→  block: Block;
 17→  blockIndex: number;
 18→  messageId: string;
 19→  onBlockChange: (
 20→    messageId: string,
 21→    blockIndex: number,
 22→    newBlock: Block,
 23→  ) => void;
 24→  children: React.ReactNode;
 25→}
 26→
 27→/**
 28→ * Read the DOM content of the editable element and construct a new Block
 29→ * that matches the original block's type, preserving type-specific fields
 30→ * (e.g. heading level, code language, list ordered flag).
 31→ */
 32→function readBlockFromDom(element: HTMLElement, original: Block): Block {
 33→  switch (original.type) {
 34→    case "paragraph":
 35→      return {
 36→        id: original.id,
 37→        type: "paragraph",
 38→        text: element.textContent ?? "",
 39→      };
 40→
 41→    case "heading":
 42→      return {
 43→        id: original.id,
 44→        type: "heading",
 45→        level: original.level,
 46→        text: element.textContent ?? "",
 47→      };
 48→
 49→    case "quote":
 50→      return {
 51→        id: original.id,
 52→        type: "quote",
 53→        text: element.textContent ?? "",
 54→      };
 55→
 56→    case "code": {
 57→      const codeEl = element.querySelector("pre code");
 58→      return {
 59→        id: original.id,
 60→        type: "code",
 61→        language: original.language,
 62→        text: codeEl ? (codeEl.textContent ?? "") : (element.textContent ?? ""),
 63→      };
 64→    }
 65→
 66→    case "list": {
 67→      const listItems = element.querySelectorAll("li");
 68→      const items = Array.from(listItems).map((li) => li.textContent ?? "");
 69→      return {
 70→        id: original.id,
 71→        type: "list",
 72→        ordered: original.ordered,
 73→        items: items.length > 0 ? items : [element.textContent ?? ""],
 74→      };
 75→    }
 76→
 77→    case "table": {
 78→      const thElements = element.querySelectorAll("th");
 79→      const headers = Array.from(thElements).map((th) => th.textContent ?? "");
 80→
 81→      const bodyRows = element.querySelectorAll("tbody tr");
 82→      const rows = Array.from(bodyRows).map((tr) => {
 83→        const cells = tr.querySelectorAll("td");
 84→        return Array.from(cells).map((td) => td.textContent ?? "");
 85→      });
 86→
 87→      return { id: original.id, type: "table", headers, rows };
 88→    }
 89→
 90→    default:
 91→      return original;
 92→  }
 93→}
 94→
 95→export function EditableBlock({
 96→  block,
 97→  blockIndex,
 98→  messageId,
 99→  onBlockChange,
100→  children,
101→}: EditableBlockProps) {
102→  const ref = useRef<HTMLDivElement>(null);
103→  // Tracks whether the last change came from the editor itself (blur commit).
104→  // When true, the useEffect below skips re-setting DOM content to avoid
105→  // fighting with the user's cursor.
106→  const isLocalChange = useRef(false);
107→
108→  // Update editor DOM when block props change externally (e.g. undo, reorder).
109→  useEffect(() => {
110→    if (isLocalChange.current) {
111→      isLocalChange.current = false;
112→      return;
113→    }
114→    const element = ref.current;
115→    if (!element) return;
116→    const currentText = element.textContent ?? "";
117→    const propText = blockToPlainText(block);
118→    if (currentText !== propText) {
119→      element.textContent = propText;
120→    }
121→  }, [block]);
122→
123→  const handleBlur = useCallback(() => {
124→    const element = ref.current;
125→    if (!element) return;
126→
127→    isLocalChange.current = true;
128→    const newBlock = readBlockFromDom(element, block);
129→    onBlockChange(messageId, blockIndex, newBlock);
130→  }, [block, blockIndex, messageId, onBlockChange]);
131→
132→  const handleKeyDown = useCallback(
133→    (event: React.KeyboardEvent<HTMLDivElement>) => {
134→      if (event.key === "Escape") {
135→        event.currentTarget.blur();
136→      }
137→    },
138→    [],
139→  );
140→
141→  const handlePaste = useCallback(
142→    (event: React.ClipboardEvent<HTMLDivElement>) => {
143→      event.preventDefault();
144→      const plainText = event.clipboardData.getData("text/plain");
145→      const selection = window.getSelection();
146→      if (selection && selection.rangeCount > 0) {
147→        const range = selection.getRangeAt(0);
148→        range.deleteContents();
149→        range.insertNode(document.createTextNode(plainText));
150→        range.collapse(false);
151→      }
152→    },
153→    [],
154→  );
155→
156→  const isCodeBlock = block.type === "code";
157→
158→  return (
159→    /* biome-ignore lint/a11y/useSemanticElements: contentEditable div wraps arbitrary block content, not a simple text input */
160→    <div
161→      ref={ref}
162→      role="textbox"
163→      tabIndex={0}
164→      data-testid="editable-block"
165→      contentEditable
166→      suppressContentEditableWarning
167→      onBlur={handleBlur}
168→      onKeyDown={handleKeyDown}
169→      onPaste={handlePaste}
170→      className={cn(
171→        "outline-none rounded-md ring-0 focus:ring-1 focus:ring-blue-300 transition-shadow",
172→        isCodeBlock && "whitespace-pre-wrap",
173→      )}
174→    >
175→      <FrozenChildren>{children}</FrozenChildren>
176→    </div>
177→  );
178→}
