 36→export function getBlockText(block: Block): string {
 37→  switch (block.type) {
 38→    case "paragraph":
 39→    case "heading":
 40→    case "quote":
 41→    case "code":
 42→      return block.text;
 43→    case "list":
 44→      return block.items.join("\n");
 45→    case "table": {
 46→      const headerLine = block.headers.join(" | ");
 47→      const rows = block.rows.map((row) => row.join(" | ")).join("\n");
 48→      return rows ? `${headerLine}\n${rows}` : headerLine;
 49→    }
 50→  }
 51→}
